    function getMealImageUrlLegacy(meal, mealType = '', plan = null) {
      if (!meal) return createFoodIllustrationDataUri('Meal', { subtitle: 'Illustrative food reference' });
      const override = meal.id ? MEAL_IMAGE_OVERRIDES[meal.id] : '';
      if (override) return override;
      const candidate = String(meal.image || '').trim();
      if (candidate) return candidate;
      const countryLabel = getCountryLabel(meal.cuisineCountry || plan?.countryPreference || NO_COUNTRY_PREFERENCE);
      return createFoodIllustrationDataUri(meal.name || `${mealType} meal`, {
        subtitle: `${countryLabel} cuisine â€¢ illustrative`,
        emoji: foodEmojiFor(meal.name || mealType || 'meal')
      });
    }

    function getMealImageFallbackUrl(meal, mealType = '', plan = null) {
      const code = String(meal?.cuisineCountry || plan?.countryPreference || NO_COUNTRY_PREFERENCE).toLowerCase();
      if (MEAL_IMAGE_FALLBACK_BY_COUNTRY[code]) return MEAL_IMAGE_FALLBACK_BY_COUNTRY[code];
      return MEAL_IMAGE_FALLBACK_BY_COUNTRY.mixed || createFoodIllustrationDataUri(meal?.name || `${mealType} meal`, {
        subtitle: 'Dish-specific placeholder image',
        emoji: foodEmojiFor(meal?.name || mealType || 'meal')
      });
    }

    function getMealImageUrl(meal, mealType = '', plan = null) {
      if (!meal) return createFoodIllustrationDataUri('Meal', { subtitle: 'Illustrative food reference' });
      const override = meal.id ? MEAL_IMAGE_OVERRIDES[meal.id] : '';
      if (override) return override;
      const candidate = String(meal.image || '').trim();
      if (candidate) return candidate;
      return getMealImageFallbackUrl(meal, mealType, plan);
    }

    function renderNutritionMeals(plan) {
      const list = document.getElementById('nutritionMealsList');
      if (!list || !plan) return;
      list.innerHTML = DAILY_MEAL_ORDER.map(type => {
        const meal = plan.meals[type];
        if (!meal) return '';
        const detailId = mealDetailId(type);
        const sourceId = sourceDetailId(type);
        const detailIngredients = (meal.ingredients || []).map(item => `<li>${item}</li>`).join('');
        const detailSteps = getMealPrepSteps(meal).map(step => `<li>${step}</li>`).join('');
        const safeCuisine = escapeHtml(getCountryLabel(meal.cuisineCountry || plan.countryPreference || NO_COUNTRY_PREFERENCE));
        const fallbackLine = meal.usedMixedFallback
          ? '<p class="meal-meta-note">No compatible local alternative was available for your filters. A mixed-cuisine substitute was used.</p>'
          : '';
        const estimateNote = escapeHtml(meal.nutritionEstimateNote || 'Estimated nutrition based on listed ingredients and serving size.');
        const servingSize = escapeHtml(meal.servingSize || '1 serving');
        const sourceListItems = renderSourceListItems(meal.nutritionSource);
        const recipeSource = escapeHtml(meal.recipeSource || 'Structured meal estimate from local seed dataset');
        const mealImage = getMealImageUrl(meal, type, plan);
        const mealImageFallback = getMealImageFallbackUrl(meal, type, plan);
        return `
          <article class="meal-card" data-meal-type="${type}">
            <img class="meal-image" src="${mealImage}" alt="${meal.name}" onerror="this.onerror=null;this.src='${mealImageFallback}';">
            <div class="meal-body">
              <div class="meal-headline">
                <strong>${type}: ${meal.name}</strong>
                <span class="meal-calories">${meal.calories} kcal</span>
              </div>
              <p class="meal-culture-badge">Cuisine: ${safeCuisine}</p>
              <p class="meal-desc">${meal.desc}</p>
              ${fallbackLine}
              <div class="macro-inline">
                <span>P ${meal.protein}g</span>
                <span>C ${meal.carbs}g</span>
                <span>F ${meal.fat}g</span>
              </div>
              <div class="meal-actions">
                <button class="meal-action-btn" type="button" data-replace-meal="${type}">Replace meal</button>
                <a class="meal-action-btn primary" href="${meal.recipeUrl}" target="_blank" rel="noopener noreferrer">View recipe</a>
                <button class="meal-action-btn" type="button" data-toggle-meal-detail="${detailId}" aria-expanded="false">Prep details</button>
              </div>
              <div class="meal-detail-collapse" id="${detailId}">
                <div class="meal-detail-body">
                  <p class="meal-meta-note"><strong>Serving size:</strong> ${servingSize}</p>
                  <p class="meal-meta-note">${estimateNote}</p>
                  <h5>Ingredients</h5>
                  <ul>${detailIngredients}</ul>
                  <h5>Preparation</h5>
                  <ol>${detailSteps}</ol>
                  <button class="meal-action-btn source-btn" type="button" data-toggle-source="${sourceId}" aria-expanded="false">Nutrition source</button>
                  <div class="meal-source-collapse" id="${sourceId}">
                    <div class="meal-source-body">
                      <p><strong>Nutrition Source</strong></p>
                      <ul>${sourceListItems}</ul>
                      <p><strong>Recipe/Cultural Source</strong></p>
                      <p>${recipeSource}</p>
                    </div>
                  </div>
                </div>
              </div>
            </div>
          </article>
        `;
      }).join('');
      list.querySelectorAll('[data-replace-meal]').forEach(button => {
        button.addEventListener('click', () => {
          const mealType = button.dataset.replaceMeal;
          regenerateNutritionPlan({ replaceType: mealType });
        });
      });
      list.querySelectorAll('[data-toggle-meal-detail]').forEach(button => {
        button.addEventListener('click', () => {
          const panelId = button.dataset.toggleMealDetail;
          const panel = panelId ? document.getElementById(panelId) : null;
          if (!panel) return;
          const opening = !panel.classList.contains('open');
          panel.classList.toggle('open', opening);
          button.setAttribute('aria-expanded', String(opening));
          button.textContent = opening ? 'Hide details' : 'Prep details';
        });
      });
      list.querySelectorAll('[data-toggle-source]').forEach(button => {
        button.addEventListener('click', () => {
          const panelId = button.dataset.toggleSource;
          const panel = panelId ? document.getElementById(panelId) : null;
          if (!panel) return;
          const opening = !panel.classList.contains('open');
          panel.classList.toggle('open', opening);
          button.setAttribute('aria-expanded', String(opening));
          button.textContent = opening ? 'Hide source' : 'Nutrition source';
        });
      });
    }

