    const FALLBACK_INGREDIENT_IMAGE = createFoodIllustrationDataUri('Food ingredient', {
      subtitle: 'Ingredient placeholder',
      emoji: 'ðŸ¥—'
    });

    function normalizeIngredientKey(value = '') {
      return String(value || '')
        .toLowerCase()
        .replace(/\([^)]*\)/g, ' ')
        .replace(/[^\w\s-]/g, ' ')
        .replace(/\s+/g, ' ')
        .trim();
    }

    function getIngredientFallbackImage(ingredientName, meal = null, plan = null) {
      const item = String(ingredientName || 'ingredient').trim();
      const cuisine = getCountryLabel(meal?.cuisineCountry || plan?.countryPreference || NO_COUNTRY_PREFERENCE);
      return createFoodIllustrationDataUri(item, {
        subtitle: `${cuisine} ingredient placeholder`,
        emoji: foodEmojiFor(item)
      });
    }

    function getIngredientImageUrl(ingredientName, meal = null, plan = null) {
      const text = normalizeIngredientKey(ingredientName);
      if (!text) return FALLBACK_INGREDIENT_IMAGE;

      const exact = INGREDIENT_IMAGE_EXACT[text];
      if (exact) return exact;

      const match = INGREDIENT_IMAGE_BY_KEYWORD.find(item => text.includes(item.key));
      if (match?.image) return match.image;

      return getIngredientFallbackImage(ingredientName, meal, plan);
    }

    function escapeHtml(value) {
      return String(value || '')
        .replace(/&/g, '&amp;')
        .replace(/</g, '&lt;')
        .replace(/>/g, '&gt;')
        .replace(/"/g, '&quot;')
        .replace(/'/g, '&#39;');
    }

    const INGREDIENT_INSIGHT_RULES = [
      { keys: ['egg', 'chicken', 'turkey', 'salmon', 'tofu', 'greek yogurt', 'protein powder'], summary: 'High-quality protein source.', benefit: 'Supports muscle repair and recovery after workouts.' },
      { keys: ['oats', 'rice', 'pasta', 'potato', 'banana', 'quinoa', 'wrap'], summary: 'Complex carbohydrate fuel.', benefit: 'Improves training energy and helps replenish glycogen.' },
      { keys: ['spinach', 'broccoli', 'greens', 'zucchini', 'carrot', 'tomato', 'cucumber', 'parsley', 'basil', 'pepper', 'onion', 'garlic'], summary: 'Micronutrient-dense produce.', benefit: 'Boosts vitamins, minerals, and antioxidant support.' },
      { keys: ['olive oil', 'avocado', 'walnut', 'flaxseed', 'sesame oil', 'almond butter'], summary: 'Healthy fat source.', benefit: 'Supports hormone balance and steady satiety.' },
      { keys: ['lentil', 'bean', 'chickpea', 'edamame', 'tofu'], summary: 'Fiber-rich plant protein.', benefit: 'Supports digestion and keeps hunger under control.' }
    ];

    function getIngredientInsight(ingredientName, plan) {
      const text = String(ingredientName || '').toLowerCase();
      const goalText = (getNutritionGoalLabel(plan?.profile?.goal || 'general-fitness') || 'general fitness').toLowerCase();
      const matched = INGREDIENT_INSIGHT_RULES.find(rule => rule.keys.some(key => text.includes(key)));
      const summary = matched ? matched.summary : 'Balanced whole-food ingredient.';
      const baseBenefit = matched ? matched.benefit : 'Supports daily nutrition balance and recovery.';
      return {
        summary,
        benefit: `${baseBenefit} Aligned with your ${goalText} plan.`
      };
    }

    function getIngredientPopoverLayer() {
      let layer = document.getElementById('ingredientPopoverLayer');
      if (!layer) {
        layer = document.createElement('div');
        layer.id = 'ingredientPopoverLayer';
        document.body.appendChild(layer);
      }
      return layer;
    }

    function openIngredientPopover(chip) {
      if (!chip) return;
      const template = chip.querySelector('.ingredient-popover');
      if (!template) return;
      const layer = getIngredientPopoverLayer();
      layer.innerHTML = '';

      const popover = template.cloneNode(true);
      popover.classList.add('ingredient-popover-floating');
      popover.dataset.side = chip.dataset.popSide === 'right' ? 'right' : 'left';
      layer.appendChild(popover);

      chip.classList.add('open');
      chip.setAttribute('aria-expanded', 'true');

      const chipRect = chip.getBoundingClientRect();
      const popRect = popover.getBoundingClientRect();
      const viewportWidth = window.innerWidth;
      const viewportHeight = window.innerHeight;
      const spacing = 10;
      const edgePadding = 8;

      let left = popover.dataset.side === 'right'
        ? chipRect.right - popRect.width
        : chipRect.left;
      left = Math.max(edgePadding, Math.min(viewportWidth - popRect.width - edgePadding, left));

      let top = chipRect.top - popRect.height - spacing;
      let placement = 'top';
      if (top < edgePadding) {
        top = chipRect.bottom + spacing;
        placement = 'bottom';
      }
      if (top + popRect.height > viewportHeight - edgePadding) {
        top = Math.max(edgePadding, viewportHeight - popRect.height - edgePadding);
      }

      popover.style.left = `${left}px`;
      popover.style.top = `${top}px`;
      popover.dataset.placement = placement;

      requestAnimationFrame(() => popover.classList.add('open'));
    }

    function closeIngredientPopovers(scope = document) {
      document.querySelectorAll('.ingredient-chip.open').forEach(chip => {
        chip.classList.remove('open');
        chip.setAttribute('aria-expanded', 'false');
      });
      const layer = document.getElementById('ingredientPopoverLayer');
      if (layer) layer.innerHTML = '';
    }

    function setupIngredientPopovers(container) {
      if (!container) return;
      const chips = container.querySelectorAll('.ingredient-chip');
      chips.forEach(chip => {
        chip.addEventListener('click', event => {
          event.stopPropagation();
          const willOpen = !chip.classList.contains('open');
          closeIngredientPopovers(document);
          if (willOpen) openIngredientPopover(chip);
        });
        chip.addEventListener('keydown', event => {
          if (event.key === 'Enter' || event.key === ' ') {
            event.preventDefault();
            chip.click();
          } else if (event.key === 'Escape') {
            chip.classList.remove('open');
            chip.setAttribute('aria-expanded', 'false');
          }
        });
      });
      if (!container.dataset.popoverScrollBound) {
        container.addEventListener('scroll', () => closeIngredientPopovers(document), { passive: true });
        container.dataset.popoverScrollBound = '1';
      }
      if (!document.body.dataset.ingredientPopoverDocBound) {
        document.addEventListener('click', event => {
          if (!container.contains(event.target)) {
            closeIngredientPopovers(document);
          }
        });
        window.addEventListener('resize', () => closeIngredientPopovers(document), { passive: true });
        window.addEventListener('scroll', () => closeIngredientPopovers(document), { passive: true });
        document.body.dataset.ingredientPopoverDocBound = '1';
      }
    }

    function renderNutritionIngredients(plan) {
      const container = document.getElementById('nutritionIngredientsList');
      if (!container || !plan) return;
      container.innerHTML = DAILY_MEAL_ORDER.map(type => {
        const meal = plan.meals[type];
        if (!meal) return '';
        const ingredients = (meal.ingredients || []).map((item, itemIndex) => {
          const imageUrl = getIngredientImageUrl(item, meal, plan);
          const imageFallback = getIngredientFallbackImage(item, meal, plan);
          const insight = getIngredientInsight(item, plan);
          const popSide = itemIndex % 2 === 1 ? 'right' : 'left';
          const safeName = escapeHtml(item);
          const safeSummary = escapeHtml(insight.summary);
          const safeBenefit = escapeHtml(insight.benefit);
          return `
            <li class="ingredient-chip" tabindex="0" role="button" aria-haspopup="dialog" aria-expanded="false" data-pop-side="${popSide}">
              <img class="ingredient-photo" src="${imageUrl}" alt="${safeName}" onerror="this.onerror=null;this.src='${imageFallback}';">
              <span class="ingredient-name">${safeName}</span>
              <div class="ingredient-popover" role="dialog" aria-label="${safeName} nutrition detail">
                <div class="ingredient-pop-header">
                  <img class="ingredient-pop-photo" src="${imageUrl}" alt="${safeName}" onerror="this.onerror=null;this.src='${imageFallback}';">
                  <div>
                    <p class="ingredient-pop-title">${safeName}</p>
                    <p class="ingredient-pop-summary">${safeSummary}</p>
                  </div>
                </div>
                <p class="ingredient-pop-benefit"><strong>Benefit:</strong> ${safeBenefit}</p>
              </div>
            </li>
          `;
        }).join('');
        return `
          <article class="ingredients-group">
            <h4>${type}: ${meal.name}</h4>
            <ul class="ingredients-grid">${ingredients}</ul>
          </article>
        `;
      }).join('');
      setupIngredientPopovers(container);
    }

    function renderNutritionSavedPlans() {
      const container = document.getElementById('nutritionSavedList');
      if (!container) return;
      const plans = nutritionState.savedPlans || [];
      if (!plans.length) {
        container.innerHTML = '<div class="saved-plan-empty">No saved nutrition plans yet. Save one to reopen it quickly.</div>';
        return;
      }
      container.innerHTML = plans.map((plan, index) => {
        const goal = getNutritionGoalLabel(plan.profile?.goal || 'general-fitness');
        const cuisine = getCountryLabel(plan.countryPreference || NO_COUNTRY_PREFERENCE);
        return `
          <article class="saved-plan-card" data-saved-index="${index}">
            <strong>${goal} â€¢ ${plan.calorieTarget} kcal</strong>
            <p class="saved-plan-meta">${formatNutritionDate(plan.createdAt)} â€¢ P ${plan.totals?.protein || 0}g / C ${plan.totals?.carbs || 0}g / F ${plan.totals?.fat || 0}g</p>
            <p class="saved-plan-meta">Cuisine preference: ${escapeHtml(cuisine)}</p>
            <div class="saved-plan-actions">
              <button class="meal-action-btn primary" type="button" data-open-saved="${index}">Open</button>
              <button class="meal-action-btn" type="button" data-delete-saved="${index}">Delete</button>
            </div>
          </article>
        `;
      }).join('');
      container.querySelectorAll('[data-open-saved]').forEach(button => {
        button.addEventListener('click', () => {
          const index = Number(button.dataset.openSaved);
          const selected = nutritionState.savedPlans[index];
          if (!selected) return;
          nutritionState.currentPlan = selected;
          nutritionState.countryPreference = normalizeCountryCode(selected.countryPreference || NO_COUNTRY_PREFERENCE);
          updateCountryPreferenceUI();
          renderNutritionPlan();
          setNutritionTab('overview');
          saveNutritionState();
        });
      });
      container.querySelectorAll('[data-delete-saved]').forEach(button => {
        button.addEventListener('click', () => {
          const index = Number(button.dataset.deleteSaved);
          if (!Number.isFinite(index)) return;
          nutritionState.savedPlans.splice(index, 1);
          saveNutritionState();
          renderNutritionSavedPlans();
        });
      });
    }

    function renderNutritionPlan() {
      const plan = nutritionState.currentPlan;
      const goalNode = document.getElementById('nutritionGoalValue');
      const targetCalNode = document.getElementById('nutritionTargetCalories');
      const planCalNode = document.getElementById('nutritionPlanCalories');
      const macroTotalsNode = document.getElementById('nutritionMacroTotals');
      updateCountryPreferenceUI();

      if (!plan) {
        if (goalNode) goalNode.textContent = 'General fitness';
        if (targetCalNode) targetCalNode.textContent = '-- kcal';
        if (planCalNode) planCalNode.textContent = '-- kcal';
        if (macroTotalsNode) macroTotalsNode.textContent = 'P -- / C -- / F --';
        renderNutritionSavedPlans();
        return;
      }

      if (goalNode) goalNode.textContent = getNutritionGoalLabel(plan.profile?.goal || 'general-fitness');
      if (targetCalNode) targetCalNode.textContent = `${plan.calorieTarget} kcal`;
      if (planCalNode) planCalNode.textContent = `${plan.totals.calories} kcal`;
      if (macroTotalsNode) macroTotalsNode.textContent = `P ${plan.totals.protein}g / C ${plan.totals.carbs}g / F ${plan.totals.fat}g`;

      renderNutritionOverview(plan);
      renderNutritionMeals(plan);
      renderMacroProgress(plan);
      renderNutritionIngredients(plan);
      renderNutritionSavedPlans();
      syncNutritionFilterChips();
    }

    function regenerateNutritionPlan(options = {}) {
      const nextPlan = buildNutritionPlan(options);
      nutritionState.currentPlan = nextPlan;
      renderNutritionPlan();
      saveNutritionState();
    }

    function saveCurrentNutritionPlan() {
      const current = nutritionState.currentPlan;
      if (!current) return;
      const stored = { ...current, id: `saved_${Date.now()}` };
      nutritionState.savedPlans = [stored, ...(nutritionState.savedPlans || []).slice(0, 11)];
      saveNutritionState();
      renderNutritionSavedPlans();
      setNutritionTab('saved');
    }
    function mqTone(value) {
      const mq = Math.max(115, Math.min(150, Number(value) || 130));
      const t = (mq - 115) / 35;
      const hue = 208 - (168 * t);
      const light = 76 - (20 * t);
      const alpha = 0.7 + (0.26 * t);
      const glowAlpha = 0.22 + (0.34 * t);
      return {
        fill: `hsla(${hue.toFixed(1)}, 92%, ${light.toFixed(1)}%, ${alpha.toFixed(3)})`,
        glow: `hsla(${hue.toFixed(1)}, 98%, 72%, ${glowAlpha.toFixed(3)})`
      };
    }

    function buildTrackingMuscleDiagramSvg(gender = 'male', mqValues = null) {
      const isFemale = gender === 'female';
      const getAvg = (leftKey, rightKey, fallback = 130) => {
        if (!mqValues) return fallback;
        const left = Number(mqValues[leftKey] || fallback);
        const right = Number(mqValues[rightKey] || fallback);
        return Math.round((left + right) / 2);
      };

      const zone = {
        shoulders: mqTone(getAvg('mqShoulderL', 'mqShoulderR', 129)),
        chest: mqTone(getAvg('mqChestL', 'mqChestR', 131)),
        biceps: mqTone(getAvg('mqBicepsL', 'mqBicepsR', 129)),
        forearms: mqTone(getAvg('mqForearmL', 'mqForearmR', 126)),
        core: mqTone(getAvg('mqAbsL', 'mqAbsR', 132)),
        quads: mqTone(getAvg('mqQuadL', 'mqQuadR', 133))
      };

      const shoulderW = isFemale ? 80 : 88;
      const torsoW = isFemale ? 56 : 60;
      const hipW = isFemale ? 64 : 60;
      return `
<svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 260 360">
  <defs>
    <linearGradient id="baseBody${gender}" x1="0" y1="0" x2="0" y2="1">
      <stop offset="0%" stop-color="#9bc9ee"/>
      <stop offset="100%" stop-color="#5a89af"/>
    </linearGradient>
    <filter id="mqGlow${gender}" x="-30%" y="-30%" width="160%" height="160%">
      <feGaussianBlur stdDeviation="2.6" result="blur"/>
      <feMerge>
        <feMergeNode in="blur"/>
        <feMergeNode in="SourceGraphic"/>
      </feMerge>
    </filter>
  </defs>

  <g opacity="0.94">
    <circle cx="130" cy="44" r="${isFemale ? 24 : 26}" fill="#d9efff" />
    <rect x="${130 - shoulderW / 2}" y="74" width="${shoulderW}" height="32" rx="16" fill="url(#baseBody${gender})"/>
    <rect x="${130 - torsoW / 2}" y="102" width="${torsoW}" height="106" rx="${isFemale ? 28 : 24}" fill="url(#baseBody${gender})"/>
    <rect x="${130 - hipW / 2}" y="194" width="${hipW}" height="42" rx="20" fill="#77a7ce"/>

    <rect x="${130 - shoulderW / 2 - 16}" y="106" width="14" height="84" rx="8" fill="#7fb2da"/>
    <rect x="${130 + shoulderW / 2 + 2}" y="106" width="14" height="84" rx="8" fill="#7fb2da"/>
    <rect x="${130 - shoulderW / 2 - 12}" y="186" width="11" height="66" rx="6" fill="#6da2cb"/>
    <rect x="${130 + shoulderW / 2 + 5}" y="186" width="11" height="66" rx="6" fill="#6da2cb"/>

    <rect x="${130 - 22}" y="236" width="18" height="108" rx="9" fill="#80b7e1"/>
    <rect x="${130 + 4}" y="236" width="18" height="108" rx="9" fill="#80b7e1"/>
  </g>

  <g filter="url(#mqGlow${gender})">
    <ellipse cx="${130 - shoulderW / 2 + 15}" cy="90" rx="13" ry="10" fill="${zone.shoulders.fill}"/>
    <ellipse cx="${130 + shoulderW / 2 - 15}" cy="90" rx="13" ry="10" fill="${zone.shoulders.fill}"/>

    <path d="M104 110 q11 -14 26 0 v28 q-12 10 -26 0 z" fill="${zone.chest.fill}"/>
    <path d="M156 110 q-11 -14 -26 0 v28 q12 10 26 0 z" fill="${zone.chest.fill}"/>

    <rect x="${130 - shoulderW / 2 - 13}" y="114" width="10" height="34" rx="5" fill="${zone.biceps.fill}"/>
    <rect x="${130 + shoulderW / 2 + 5}" y="114" width="10" height="34" rx="5" fill="${zone.biceps.fill}"/>

    <rect x="${130 - shoulderW / 2 - 10}" y="158" width="8" height="34" rx="4" fill="${zone.forearms.fill}"/>
    <rect x="${130 + shoulderW / 2 + 6}" y="158" width="8" height="34" rx="4" fill="${zone.forearms.fill}"/>

    <rect x="118" y="140" width="24" height="58" rx="10" fill="${zone.core.fill}"/>
    <ellipse cx="124" cy="160" rx="5.5" ry="11" fill="rgba(227,248,255,0.48)"/>
    <ellipse cx="136" cy="160" rx="5.5" ry="11" fill="rgba(227,248,255,0.48)"/>

    <rect x="108" y="238" width="12" height="56" rx="6" fill="${zone.quads.fill}"/>
    <rect x="140" y="238" width="12" height="56" rx="6" fill="${zone.quads.fill}"/>
  </g>
</svg>`.trim();
    }

    function getTrackingGraphicDataUri(gender = 'male', mqValues = null) {
      const normalizedGender = gender === 'female' ? 'female' : 'male';
      return svgToDataUri(buildTrackingMuscleDiagramSvg(normalizedGender, mqValues));
    }
    function rgbToCssVar(rgb) {
      return `${Math.max(0, Math.min(255, Math.round(rgb[0])))} ${Math.max(0, Math.min(255, Math.round(rgb[1])))} ${Math.max(0, Math.min(255, Math.round(rgb[2])))}`.replace(/\s/g, ', ');
    }

    function enhanceAccent(rgb, gain = 1.12) {
      const [r, g, b] = rgb;
      const avg = (r + g + b) / 3;
      return [
        Math.min(255, avg + (r - avg) * gain),
        Math.min(255, avg + (g - avg) * gain),
        Math.min(255, avg + (b - avg) * gain)
      ];
    }

    function sampleRgbAt(ctx, x, y) {
      const pixel = ctx.getImageData(x, y, 1, 1).data;
      return [pixel[0], pixel[1], pixel[2]];
    }

    function rgbToHsl(rgb) {
      const r = (rgb[0] || 0) / 255;
      const g = (rgb[1] || 0) / 255;
      const b = (rgb[2] || 0) / 255;
      const max = Math.max(r, g, b);
      const min = Math.min(r, g, b);
      const lightness = (max + min) / 2;
      const delta = max - min;
      let hue = 0;
      let saturation = 0;
      if (delta !== 0) {
        saturation = lightness > 0.5 ? delta / (2 - max - min) : delta / (max + min);
        if (max === r) hue = ((g - b) / delta + (g < b ? 6 : 0)) * 60;
        else if (max === g) hue = ((b - r) / delta + 2) * 60;
        else hue = ((r - g) / delta + 4) * 60;
      }
      return [hue, saturation, lightness];
    }

    function colorDistance(a, b) {
      return Math.hypot((a[0] || 0) - (b[0] || 0), (a[1] || 0) - (b[1] || 0), (a[2] || 0) - (b[2] || 0));
    }

    function extractVibrantPalette(ctx, width, height) {
      const imageData = ctx.getImageData(0, 0, width, height).data;
      const buckets = new Map();
      for (let i = 0; i < imageData.length; i += 4) {
        const alpha = imageData[i + 3];
        if (alpha < 220) continue;
        const r = imageData[i];
        const g = imageData[i + 1];
        const b = imageData[i + 2];
        const [hue, saturation, lightness] = rgbToHsl([r, g, b]);
        if (saturation < 0.16 || lightness < 0.12 || lightness > 0.9) continue;
        const qr = Math.round(r / 24) * 24;
        const qg = Math.round(g / 24) * 24;
        const qb = Math.round(b / 24) * 24;
        const key = `${qr},${qg},${qb}`;
        const existing = buckets.get(key) || { count: 0, r: 0, g: 0, b: 0, sat: 0, lum: 0, hue: 0 };
        existing.count += 1;
        existing.r += r;
        existing.g += g;
        existing.b += b;
        existing.sat += saturation;
        existing.lum += lightness;
        existing.hue += hue;
        buckets.set(key, existing);
      }
      const entries = [...buckets.values()].map(bucket => {
        const inv = 1 / bucket.count;
        const rgb = [bucket.r * inv, bucket.g * inv, bucket.b * inv];
        const sat = bucket.sat * inv;
        const lum = bucket.lum * inv;
        const vividScore = sat * 1.4 + (1 - Math.abs(lum - 0.54)) * 0.28 + Math.log10(bucket.count + 2) * 0.34;
        return { rgb, sat, lum, vividScore };
      }).sort((a, b) => b.vividScore - a.vividScore);

      if (!entries.length) return null;
      const first = entries[0].rgb;
      const second = (entries.find(entry => colorDistance(entry.rgb, first) > 54) || entries[1] || entries[0]).rgb;
      const third = (entries.find(entry =>
        colorDistance(entry.rgb, first) > 36 && colorDistance(entry.rgb, second) > 36
      ) || entries[2] || entries[0]).rgb;
      return [first, second, third];
    }

    function applyDashAccentPalette(a, b, c) {
      document.querySelectorAll('.reference-dashboard').forEach(panel => {
        panel.style.setProperty('--dash-accent-a-rgb', rgbToCssVar(a));
        panel.style.setProperty('--dash-accent-b-rgb', rgbToCssVar(b));
        panel.style.setProperty('--dash-accent-c-rgb', rgbToCssVar(c));
      });
    }

    function applyUiVibrantPalette(a, b, c) {
      const root = document.documentElement;
      if (!root) return;
      const cssA = rgbToCssVar(a);
      const cssB = rgbToCssVar(b);
      const cssC = rgbToCssVar(c);
      root.style.setProperty('--ui-vibrant-a-rgb', cssA);
      root.style.setProperty('--ui-vibrant-b-rgb', cssB);
      root.style.setProperty('--ui-vibrant-c-rgb', cssC);
      root.style.setProperty('--dash-accent-a-rgb', cssA);
      root.style.setProperty('--dash-accent-b-rgb', cssB);
      root.style.setProperty('--dash-accent-c-rgb', cssC);
      root.style.setProperty('--accent', `rgb(${cssA})`);
      root.style.setProperty('--accent-blue', `rgb(${cssA})`);
      root.style.setProperty('--accent-warm', `rgb(${cssC})`);
    }

    function sampleAndApplyPaletteFromImage(imageSource, dashboard) {
      const canvas = document.createElement('canvas');
      const sampleW = 72;
      const sampleH = 72;
      canvas.width = sampleW;
      canvas.height = sampleH;
      const ctx = canvas.getContext('2d', { willReadFrequently: true });
      if (!ctx) return false;
      ctx.drawImage(imageSource, 0, 0, sampleW, sampleH);
      const extracted = extractVibrantPalette(ctx, sampleW, sampleH);
      const fallbackA = enhanceAccent(sampleRgbAt(ctx, 58, 14), 1.34);
      const fallbackB = enhanceAccent(sampleRgbAt(ctx, 50, 47), 1.28);
      const fallbackC = enhanceAccent(sampleRgbAt(ctx, 22, 30), 1.26);
      const a = enhanceAccent(extracted?.[0] || fallbackA, 1.3);
      const b = enhanceAccent(extracted?.[1] || fallbackB, 1.22);
      const c = enhanceAccent(extracted?.[2] || fallbackC, 1.26);
      applyUiVibrantPalette(a, b, c);
      applyDashAccentPalette(a, b, c);
      if (dashboard) {
        dashboard.style.setProperty('--dash-accent-a-rgb', rgbToCssVar(a));
        dashboard.style.setProperty('--dash-accent-b-rgb', rgbToCssVar(b));
        dashboard.style.setProperty('--dash-accent-c-rgb', rgbToCssVar(c));
      }
      return true;
    }

    function applyAccentFromCoverImage() {
      const dashboard = document.querySelector('.reference-dashboard');
      const coverImage = document.getElementById('coverImage');
      if (!coverImage || !coverImage.complete || !coverImage.naturalWidth) return false;
      try {
        return sampleAndApplyPaletteFromImage(coverImage, dashboard);
      } catch (_error) {
        return false;
      }
    }

    function applyDashboardAdaptiveAccent() {
      const dashboard = document.querySelector('.reference-dashboard');
      const bgLayer = dashboard?.querySelector('.ref-bg-photo');
      if (!dashboard || !bgLayer) return;
      // Always prioritize the user cover image from page 1 for accent extraction.
      if (applyAccentFromCoverImage()) return;
      const coverImage = document.getElementById('coverImage');
      if (coverImage && coverImage.src) {
        const coverSampler = new Image();
        coverSampler.decoding = 'async';
        coverSampler.crossOrigin = 'anonymous';
        coverSampler.src = coverImage.currentSrc || coverImage.src;
        coverSampler.onload = () => {
          try {
            if (sampleAndApplyPaletteFromImage(coverSampler, dashboard)) return;
          } catch (_error) {
            // Fallback handled below.
          }
        };
      }
      const computed = getComputedStyle(bgLayer).backgroundImage || '';
      const urls = [...computed.matchAll(/url\(["']?([^"')]+)["']?\)/g)].map(match => match[1]);
      const imageUrl = urls.length ? urls[urls.length - 1] : '';
      if (!imageUrl) return;
      const img = new Image();
      img.decoding = 'async';
      img.crossOrigin = 'anonymous';
      img.src = imageUrl;
      img.onload = () => {
        try {
          sampleAndApplyPaletteFromImage(img, dashboard);
        } catch (_error) {
          // Keep fallback accent colors if sampling fails.
        }
      };
    }
    const BODY_TYPE_GOAL_WEEKS_BASE = {
      ectomorph: 10,
      mesomorph: 8,
      endomorph: 12
    };
    let bodyTypeDetailHideTimer = null;

    function clearBodyTypeDetailHideTimer() {
      if (bodyTypeDetailHideTimer) {
        window.clearTimeout(bodyTypeDetailHideTimer);
        bodyTypeDetailHideTimer = null;
      }
    }

    function showBodyTypeDetail() {
      const panel = document.querySelector('.bodytype-panel');
      if (!panel) return;
      clearBodyTypeDetailHideTimer();
      panel.classList.add('show-detail');
    }

    function hideBodyTypeDetail() {
      const panel = document.querySelector('.bodytype-panel');
      if (!panel) return;
      panel.classList.remove('show-detail');
    }

    function scheduleBodyTypeDetailHide(delayMs = 880) {
      clearBodyTypeDetailHideTimer();
      bodyTypeDetailHideTimer = window.setTimeout(() => {
        hideBodyTypeDetail();
      }, delayMs);
    }

    function suggestGoalDurationWeeks(bodyType, age, category, gender = 'male') {
      const normalizedBodyType = ['ectomorph', 'mesomorph', 'endomorph'].includes(bodyType) ? bodyType : 'mesomorph';
      const normalizedAge = clampNumber(age, 10, 90, 28);
      const normalizedCategory = category || 'Smart';
      const normalizedGender = gender === 'female' ? 'female' : 'male';
      const categoryOffset = {
        Underweight: 2,
        Normal: 0,
        Overweight: 2,
        Obese: 4,
        Smart: 1
      };
      const genderOffset = {
        male: 0,
        female: 1
      };
      let recommendedWeeks = BODY_TYPE_GOAL_WEEKS_BASE[normalizedBodyType] || BODY_TYPE_GOAL_WEEKS_BASE.mesomorph;
      recommendedWeeks += categoryOffset[normalizedCategory] || 0;
      recommendedWeeks += genderOffset[normalizedGender] || 0;
      if (normalizedAge >= 55) recommendedWeeks += 2;
      if (normalizedAge <= 24) recommendedWeeks -= 1;
      return clampNumber(recommendedWeeks, 4, 24, 8);
    }

    function formatBodyTypeLabel(bodyType) {
      if (bodyType === 'ectomorph') return 'Ectomorph';
      if (bodyType === 'endomorph') return 'Endomorph';
      return 'Mesomorph';
    }

    function refreshGoalDurationSuggestion(preferredCategory = null) {
      const bodyTypeInput = document.getElementById('bodyTypeInput');
      const ageInput = document.getElementById('ageInput');
      const genderInput = document.getElementById('genderInput');
      const goalWeeksInput = document.getElementById('goalWeeksInput');
      const goalWeeksHint = document.getElementById('goalWeeksHint');
      if (!bodyTypeInput || !ageInput || !goalWeeksInput || !goalWeeksHint) return;
      const bodyType = bodyTypeInput.value || 'mesomorph';
      const age = clampNumber(ageInput.value, 10, 90, 28);
      const gender = String(genderInput?.value || profileState.gender || 'male').toLowerCase() === 'female' ? 'female' : 'male';
      const category = preferredCategory || lastCategory || 'Smart';
      const suggestedWeeks = suggestGoalDurationWeeks(bodyType, age, category, gender);
      goalWeeksInput.value = String(suggestedWeeks);
      goalWeeksHint.textContent = `Suggested ${suggestedWeeks} weeks for ${formatBodyTypeLabel(bodyType)}, ${gender}, age ${age}, and ${category} BMI profile.`;
    }

    function getGuidedSetupDefinitions() {
      return [
        { key: 'height', fieldId: 'heightInput', required: true, type: 'number' },
        { key: 'weight', fieldId: 'weightInput', required: true, type: 'number' },
        { key: 'age', fieldId: 'ageInput', required: true, type: 'number' },
        { key: 'bodyType', fieldId: 'bodyTypeInput', required: true, type: 'select' },
        { key: 'gender', fieldId: 'genderInput', required: true, type: 'select' },
        { key: 'goalWeeks', fieldId: 'goalWeeksInput', required: true, type: 'number' },
        { key: 'fitnessGoal', fieldId: 'fitnessGoalInput', required: true, type: 'select' },
        { key: 'activityLevel', fieldId: 'activityLevelInput', required: true, type: 'select' },
        { key: 'dietaryPreference', fieldId: 'dietaryPreferenceInput', required: true, type: 'select' },
        { key: 'allergies', fieldId: 'allergiesInput', required: false, type: 'text' },
        { key: 'experience', fieldId: 'experienceInput', required: true, type: 'select' },
        { key: 'limitations', fieldId: 'limitationsInput', required: false, type: 'text' }
      ];
    }

    function setupStepValue(step) {
      const field = document.getElementById(step.fieldId);
      if (!field) return '';
      if (step.key === 'gender') return getSelectedGender();
      if (step.key === 'bodyType') return String(field.value || 'mesomorph');
      return String(field.value ?? '').trim();
    }

    function isSetupStepValid(step) {
      const raw = setupStepValue(step);
      if (!step.required && !raw) return true;
      if (step.key === 'height') return clampNumber(raw, 100, 230, 0) > 0;
      if (step.key === 'weight') return clampNumber(raw, 30, 260, 0) > 0;
      if (step.key === 'age') return clampNumber(raw, 10, 90, 0) > 0;
      if (step.key === 'goalWeeks') return clampNumber(raw, 1, 24, 0) > 0;
      if (step.key === 'bodyType') return ['ectomorph', 'mesomorph', 'endomorph'].includes(raw.toLowerCase());
      if (step.key === 'gender') return ['male', 'female'].includes(raw.toLowerCase());
      if (step.type === 'select') return raw.length > 0;
      return raw.length > 0 || !step.required;
    }

    function formatSetupStepSummary(step) {
      const field = document.getElementById(step.fieldId);
      const raw = setupStepValue(step);
      if (!raw && !step.required) return 'Not specified';
      if (step.key === 'bodyType') return formatBodyTypeLabel(raw.toLowerCase());
      if (step.key === 'gender') return raw.charAt(0).toUpperCase() + raw.slice(1);
      if (step.key === 'fitnessGoal') return getNutritionGoalLabel(normalizeGoal(raw || 'auto'));
      if (step.key === 'dietaryPreference') return raw ? raw.replace(/-/g, ' ').replace(/\b\w/g, ch => ch.toUpperCase()) : 'Balanced';
      if (step.key === 'activityLevel') return raw ? raw.replace(/\b\w/g, ch => ch.toUpperCase()) : 'Moderate';
      if (step.type === 'select' && field?.selectedOptions?.[0]) return field.selectedOptions[0].textContent.trim();
      return raw || 'Not set';
    }

    function focusSetupStep(index, smooth = true) {
      const step = guidedSetupState.steps[index];
      if (!step) return;
      const target = step.focusEl || step.group;
      if (!target) return;
      if (!guidedSetupState.reducedMotion && smooth) {
        target.scrollIntoView({ behavior: 'smooth', block: 'center' });
      } else {
        target.scrollIntoView({ behavior: 'auto', block: 'center' });
      }
      const focusField = step.focusEl;
      if (focusField && (focusField.tagName === 'INPUT' || focusField.tagName === 'SELECT' || focusField.tagName === 'TEXTAREA')) {
        window.setTimeout(() => {
          try { focusField.focus({ preventScroll: true }); } catch (_err) {}
        }, guidedSetupState.reducedMotion ? 0 : 160);
      }
    }

    function updateSetupProgressUI() {
      const fill = document.getElementById('setupProgressFill');
      const label = document.getElementById('setupProgressText');
      const requiredSteps = guidedSetupState.steps.filter(step => step.required);
      const completedRequired = requiredSteps.reduce((count, step) => count + (isSetupStepValid(step) ? 1 : 0), 0);
      const total = Math.max(1, requiredSteps.length);
      const pct = Math.round((completedRequired / total) * 100);
      if (fill) fill.style.width = `${pct}%`;
      if (label) label.textContent = `Step ${Math.min(guidedSetupState.currentIndex + 1, guidedSetupState.steps.length)} of ${guidedSetupState.steps.length} â€¢ ${pct}% complete`;
      const backBtn = document.getElementById('setupBackBtn');
      if (backBtn) backBtn.disabled = guidedSetupState.currentIndex <= 0;
    }

    function renderSetupStepStates(pulseSuccessIndex = -1) {
      guidedSetupState.steps.forEach((step, index) => {
        const group = step.group;
        if (!group) return;
        const isActive = index === guidedSetupState.currentIndex;
        const isPast = index < guidedSetupState.currentIndex;
        const isComplete = isPast || (isActive && isSetupStepValid(step) && !step.required && !setupStepValue(step));
        group.classList.toggle('is-active', isActive);
        group.classList.toggle('is-pending', !isActive && !isPast);
        group.classList.toggle('is-complete', isPast);
        const hint = group.querySelector('.setup-step-hint');
        if (hint) {
          if (isActive && step.required && !isSetupStepValid(step)) {
            hint.classList.add('error');
            hint.textContent = 'Complete this field to continue.';
          } else {
            hint.classList.remove('error');
            hint.textContent = step.required ? 'Auto-advances when complete.' : 'Optional';
          }
        }
        const summary = group.querySelector('.setup-summary-value');
        if (summary) summary.textContent = formatSetupStepSummary(step);
        if (pulseSuccessIndex === index) {
          group.classList.remove('success-pulse');
          void group.offsetWidth;
          group.classList.add('success-pulse');
        }
      });
      updateSetupProgressUI();
    }

    function blurActiveField() {
      const active = document.activeElement;
      if (active && (active.tagName === 'INPUT' || active.tagName === 'TEXTAREA' || active.tagName === 'SELECT')) {
        try { active.blur(); } catch (_err) {}
      }
    }

    function findFirstIncompleteRequiredStepIndex() {
      const index = guidedSetupState.steps.findIndex(step => step.required && !isSetupStepValid(step));
      return index === -1 ? guidedSetupState.steps.length - 1 : index;
    }

    function triggerSetupAutoPageAdvance() {
      const page = document.body?.dataset?.currentPage || '';
      if (page !== 'bmi') return;
      if (guidedSetupState.transitionLock) return;
      guidedSetupState.transitionLock = true;
      const calculateBtn = document.getElementById('calculateBtn');
      if (calculateBtn) {
        calculateBtn.classList.add('success-pulse');
        window.setTimeout(() => calculateBtn.classList.remove('success-pulse'), 520);
        try {
          calculateBtn.scrollIntoView({
            behavior: guidedSetupState.reducedMotion ? 'auto' : 'smooth',
            block: 'center'
          });
        } catch (_err) {}
      }
      window.setTimeout(() => {
        guidedSetupState.transitionLock = false;
      }, guidedSetupState.reducedMotion ? 140 : 480);
    }

    function goToSetupStep(index, pulseIndex = -1) {
      const bounded = Math.max(0, Math.min(guidedSetupState.steps.length - 1, index));
      guidedSetupState.currentIndex = bounded;
      renderSetupStepStates(pulseIndex);
      focusSetupStep(bounded, true);
    }

    function moveToNextSetupStep(trigger = 'manual') {
      const currentStep = guidedSetupState.steps[guidedSetupState.currentIndex];
      if (!currentStep) return;
      if (currentStep.required && !isSetupStepValid(currentStep)) {
        renderSetupStepStates(-1);
        return;
      }
      blurActiveField();
      const nextIndex = guidedSetupState.currentIndex + 1;
      if (nextIndex < guidedSetupState.steps.length) {
        goToSetupStep(nextIndex, guidedSetupState.currentIndex);
      } else {
        renderSetupStepStates(guidedSetupState.currentIndex);
        if (trigger !== 'manual' || isSetupStepValid(currentStep)) {
          triggerSetupAutoPageAdvance();
        }
      }
    }

    function scheduleSetupAutoAdvance(stepKey, delayMs = 520) {
      if (guidedSetupState.autoTimer) {
        window.clearTimeout(guidedSetupState.autoTimer);
        guidedSetupState.autoTimer = null;
      }
      const index = guidedSetupState.steps.findIndex(step => step.key === stepKey);
      if (index === -1 || index !== guidedSetupState.currentIndex) return;
      const step = guidedSetupState.steps[index];
      if (step.required && !isSetupStepValid(step)) return;
      guidedSetupState.autoTimer = window.setTimeout(() => {
        moveToNextSetupStep('auto');
      }, guidedSetupState.reducedMotion ? 90 : delayMs);
    }

    function openSetupStepForEdit(stepKey) {
      const index = guidedSetupState.steps.findIndex(step => step.key === stepKey);
      if (index === -1) return;
      goToSetupStep(index);
    }

    function bindSetupStepEvents(step) {
      const field = document.getElementById(step.fieldId);
      if (!field) return;
      const isTyped = step.type === 'number' || step.type === 'text';
      if (step.type === 'select') {
        field.addEventListener('change', () => {
          renderSetupStepStates();
          scheduleSetupAutoAdvance(step.key, 260);
          recalculateDependentPlans();
        });
      }
      if (isTyped) {
        field.addEventListener('keydown', event => {
          if (event.key === 'Enter') {
            event.preventDefault();
            if (isSetupStepValid(step)) moveToNextSetupStep('enter');
          }
        });
        field.addEventListener('blur', () => {
          renderSetupStepStates();
          if (isSetupStepValid(step)) {
            scheduleSetupAutoAdvance(step.key, 240);
            recalculateDependentPlans();
          }
        });
        field.addEventListener('input', () => {
          renderSetupStepStates();
          if (isSetupStepValid(step)) scheduleSetupAutoAdvance(step.key, step.required ? 720 : 900);
        });
      }
    }

    function initGuidedSetupFlow() {
      if (guidedSetupState.initialized) return;
      const grid = document.querySelector('#profile .ref-input-grid');
      if (!grid) return;
      const defs = getGuidedSetupDefinitions();
      guidedSetupState.steps = defs.map(def => {
        const field = document.getElementById(def.fieldId);
        const group = field?.closest('.input-group') || null;
        if (!group) return null;
        group.classList.add('setup-step');
        group.dataset.setupStep = def.key;
        if (!group.querySelector('.setup-step-summary')) {
          const summary = document.createElement('div');
          summary.className = 'setup-step-summary';
          summary.setAttribute('role', 'button');
          summary.setAttribute('tabindex', '0');
          summary.setAttribute('aria-label', `Edit ${def.label}`);
          summary.innerHTML = `
            <span class="setup-summary-value"></span>
            <span class="setup-summary-actions">
              <span class="setup-summary-check">âœ“</span>
            </span>
          `;
          group.appendChild(summary);
          summary.addEventListener('click', event => {
            event.preventDefault();
            event.stopPropagation();
            openSetupStepForEdit(def.key);
          });
          summary.addEventListener('keydown', event => {
            if (event.key === 'Enter' || event.key === ' ') {
              event.preventDefault();
              openSetupStepForEdit(def.key);
            }
          });
        }
        if (!group.querySelector('.setup-step-hint')) {
          const hint = document.createElement('p');
          hint.className = 'setup-step-hint';
          hint.textContent = def.required ? 'Auto-advances when complete.' : 'Optional';
          group.appendChild(hint);
        }
        return {
          ...def,
          group,
          focusEl:
            def.key === 'gender'
              ? document.getElementById('genderMenuTrigger')
              : def.key === 'bodyType'
                ? document.getElementById('bodyTypeMenuTrigger')
                : field
        };
      }).filter(Boolean);
      if (!guidedSetupState.steps.length) return;
      guidedSetupState.currentIndex = findFirstIncompleteRequiredStepIndex();
      guidedSetupState.initialized = true;
      guidedSetupState.steps.forEach(step => bindSetupStepEvents(step));
      const backBtn = document.getElementById('setupBackBtn');
      if (backBtn) backBtn.addEventListener('click', () => goToSetupStep(guidedSetupState.currentIndex - 1));
      renderSetupStepStates();
    }

    function syncGuidedSetupFlow() {
      if (!guidedSetupState.initialized) return;
      const nextIncomplete = findFirstIncompleteRequiredStepIndex();
      if (nextIncomplete < guidedSetupState.currentIndex) {
        guidedSetupState.currentIndex = nextIncomplete;
      }
      renderSetupStepStates();
    }

    function recalculateDependentPlans() {
      // Keep setup/profile changes reactive without auto-generating the workout plan.
      // Plan generation should only run on explicit "Generate Plan" tap.
      refreshGoalDurationSuggestion();
      updateActivityTracker();
      regenerateNutritionPlan();
    }

    function resolvePageDirection(currentPageName, nextPageName) {
      const currentIndex = PAGE_ORDER.indexOf(currentPageName);
      const nextIndex = PAGE_ORDER.indexOf(nextPageName);
      if (currentIndex === -1 || nextIndex === -1) return 1;
      if (nextIndex === currentIndex) return 1;
      return nextIndex > currentIndex ? 1 : -1;
    }

    function normalizeHandle(handle) {
      const clean = (handle || '').trim().replace(/\s+/g, '');
      if (!clean) return defaultProfile.handle;
      return clean.startsWith('@') ? clean : `@${clean}`;
    }

    function updateBodyTypeGuide() {
      const bodyTypeInput = document.getElementById('bodyTypeInput');
      const bodyTypeDescription = document.getElementById('bodyTypeDescription');
      const bodyTypePreview = document.getElementById('bodyTypePreview');
      const chips = document.querySelectorAll('.bodytype-chip');
      const value = bodyTypeInput?.value || 'mesomorph';
      const guide = BODY_TYPE_GUIDE[value] || BODY_TYPE_GUIDE.mesomorph;
      const gender = getSelectedGender();
      applyBodyTypeImagesForGender(gender);
      chips.forEach(chip => {
        chip.classList.toggle('active', chip.dataset.bodyType === value);
      });
      syncBodyTypeMenuUI();
      if (bodyTypePreview) {
        const selectedChip = document.querySelector(`.bodytype-chip[data-body-type="${value}"]`);
        const figureSvg = selectedChip?.querySelector('.bodytype-photo')?.outerHTML || '';
        const title = selectedChip?.querySelector('strong')?.textContent || 'Mesomorph';
        const subtitle = selectedChip?.querySelector('em')?.textContent || 'Athletic build';
        const genderLabel = gender === 'female' ? 'Female' : 'Male';
        bodyTypePreview.innerHTML = `
          <div class="bodytype-preview-figure">${figureSvg}</div>
          <div class="bodytype-preview-copy">
            <strong>${title} - ${genderLabel}</strong>
            <span>${subtitle}</span>
            <span class="bodytype-preview-note">${guide.preview}</span>
          </div>
        `;
        bodyTypePreview.classList.remove('zoom-reveal');
        void bodyTypePreview.offsetWidth;
        bodyTypePreview.classList.add('zoom-reveal');
      }
      if (bodyTypeDescription) {
        bodyTypeDescription.innerHTML = `
          <p>${guide.summary}</p>
          <ul>${guide.tips.map(tip => `<li>${tip}</li>`).join('')}</ul>
        `;
      }
      refreshGoalDurationSuggestion();
    }

    function loadStoredState() {
      try {
        const profileRaw = localStorage.getItem(PROFILE_STORAGE_KEY);
        if (profileRaw) {
          const parsed = JSON.parse(profileRaw);
          profileState = {
            name: parsed.name || defaultProfile.name,
            handle: normalizeHandle(parsed.handle || defaultProfile.handle),
            bio: parsed.bio || defaultProfile.bio,
            gender: String(parsed.gender || defaultProfile.gender).toLowerCase() === 'female' ? 'female' : 'male',
            fitnessGoal: normalizeGoal(parsed.fitnessGoal || defaultProfile.fitnessGoal),
            activityLevel: String(parsed.activityLevel || defaultProfile.activityLevel || 'moderate').toLowerCase(),
            dietaryPreference: String(parsed.dietaryPreference || defaultProfile.dietaryPreference || 'balanced').toLowerCase(),
            allergies: String(parsed.allergies || defaultProfile.allergies || ''),
            experience: String(parsed.experience || defaultProfile.experience || 'beginner').toLowerCase(),
            limitations: String(parsed.limitations || defaultProfile.limitations || '')
          };
        }
      } catch (_error) {}
      try {
        const progressRaw = localStorage.getItem(PROGRESS_STORAGE_KEY);
        if (progressRaw) {
          const parsed = JSON.parse(progressRaw);
          progressState = {
            completedExercises: parsed.completedExercises || {},
            completedDays: parsed.completedDays || {},
            dailyActivity: parsed.dailyActivity || {},
            lastActivityAt: parsed.lastActivityAt || 0,
            hardwareActivityCount: parsed.hardwareActivityCount || 0,
            exercisePulseCounts: parsed.exercisePulseCounts || {}
          };
        }
      } catch (_error) {}
      try {
        const coverRaw = localStorage.getItem(COVER_STORAGE_KEY);
        if (coverRaw) coverImageState = coverRaw;
      } catch (_error) {}
      try {
        const coverSettingsRaw = localStorage.getItem(COVER_SETTINGS_STORAGE_KEY);
        if (coverSettingsRaw) {
          const parsed = JSON.parse(coverSettingsRaw);
          coverSettingsState = {
            headerLabel: String(parsed.headerLabel || defaultCoverSettings.headerLabel || 'Profile').trim() || 'Profile',
            displayName: String(parsed.displayName || '').trim(),
            goalBadge: String(parsed.goalBadge || defaultCoverSettings.goalBadge || '@goal-smart').trim() || '@goal-smart',
            quote: String(parsed.quote || defaultCoverSettings.quote || '"Small effort, every day. Big change, every month."').trim()
          };
        }
      } catch (_error) {}
      try {
        const themeRaw = localStorage.getItem(THEME_STORAGE_KEY);
        if (themeRaw) {
          const parsed = JSON.parse(themeRaw);
          const pref = String(parsed.preference || '').toLowerCase();
          themeState.preference = pref === 'light' || pref === 'dark' || pref === 'system' ? pref : 'system';
          themeState.resolved = themeState.preference === 'light' || themeState.preference === 'dark'
            ? themeState.preference
            : 'dark';
        }
      } catch (_error) {}
      try {
        const nutritionRaw = localStorage.getItem(NUTRITION_STORAGE_KEY);
        if (nutritionRaw) {
          const parsed = JSON.parse(nutritionRaw);
          nutritionState = {
            activeTab: ['overview', 'meals', 'macros', 'ingredients', 'saved'].includes(parsed.activeTab) ? parsed.activeTab : 'overview',
            activeFilters: Array.isArray(parsed.activeFilters) ? parsed.activeFilters.filter(filter => NUTRITION_FILTERS.includes(filter)) : [],
            countryPreference: normalizeCountryCode(parsed.countryPreference || NO_COUNTRY_PREFERENCE),
            countrySearch: normalizeCountrySearch(parsed.countrySearch || ''),
            currentPlan: parsed.currentPlan || null,
            savedPlans: Array.isArray(parsed.savedPlans) ? parsed.savedPlans : []
          };
        }
      } catch (_error) {}
    }

    function saveProfile() {
      localStorage.setItem(PROFILE_STORAGE_KEY, JSON.stringify(profileState));
    }

    function saveProgress() {
      localStorage.setItem(PROGRESS_STORAGE_KEY, JSON.stringify(progressState));
    }

    function saveCoverImage(src) {
      coverImageState = src || '';
      localStorage.setItem(COVER_STORAGE_KEY, coverImageState);
    }

    function saveCoverSettings() {
      localStorage.setItem(COVER_SETTINGS_STORAGE_KEY, JSON.stringify(coverSettingsState));
    }

    function normalizeThemePreference(value) {
      const pref = String(value || '').toLowerCase();
      if (pref === 'light' || pref === 'dark') return pref;
      return 'system';
    }

    function detectSystemTheme() {
      if (typeof window !== 'undefined' && window.matchMedia && window.matchMedia('(prefers-color-scheme: light)').matches) {
        return 'light';
      }
      return 'dark';
    }

    function resolveTheme(preference) {
      const pref = normalizeThemePreference(preference);
      if (pref === 'system') return detectSystemTheme();
      return pref;
    }

    function updateThemeMetaColor(resolvedTheme) {
      const meta = document.querySelector('meta[name="theme-color"]');
      if (!meta) return;
      meta.setAttribute('content', resolvedTheme === 'light' ? '#edf4fb' : '#131517');
    }

    function saveThemePreference() {
      localStorage.setItem(THEME_STORAGE_KEY, JSON.stringify({
        preference: themeState.preference,
        resolved: themeState.resolved
      }));
    }

    function applyThemePreference(preference, options = {}) {
      const settings = {
        persist: true,
        ...options
      };
      themeState.preference = normalizeThemePreference(preference);
      themeState.resolved = resolveTheme(themeState.preference);
      document.body.dataset.themePreference = themeState.preference;
      document.body.dataset.themeResolved = themeState.resolved;
      updateThemeMetaColor(themeState.resolved);
      if (settings.persist) saveThemePreference();
    }

    function onSystemThemeChanged() {
      if (themeState.preference !== 'system') return;
      applyThemePreference('system', { persist: false });
    }

    function initSystemThemeListener() {
      if (typeof window === 'undefined' || !window.matchMedia) return;
      systemThemeMediaQuery = window.matchMedia('(prefers-color-scheme: light)');
      if (typeof systemThemeMediaQuery.addEventListener === 'function') {
        systemThemeMediaQuery.addEventListener('change', onSystemThemeChanged);
      } else if (typeof systemThemeMediaQuery.addListener === 'function') {
        systemThemeMediaQuery.addListener(onSystemThemeChanged);
      }
    }

    function openProfileSetupFromCover() {
      closeCoverMenu();
      showPage('bmi');
      window.setTimeout(() => {
        const target = document.getElementById('profile');
        if (target) target.scrollIntoView({ behavior: 'smooth', block: 'start' });
        const firstField = document.getElementById('heightInput');
        if (firstField) firstField.focus();
      }, PAGE_TRANSITION_MS - 90);
    }

    function getEffectiveCoverName() {
      return (coverSettingsState.displayName || '').trim() || profileState.name;
    }

    let coverQuoteDailyTimer = null;
    function getDayOfYear(date = new Date()) {
      const start = new Date(date.getFullYear(), 0, 0);
      const diff = date - start;
      const oneDay = 1000 * 60 * 60 * 24;
      return Math.floor(diff / oneDay);
    }

    function getDailyCoverQuote() {
      const now = new Date();
      const daySeed = getDayOfYear(now) + (now.getFullYear() * 13);
      const quoteIndex = Math.abs(daySeed) % DAILY_COVER_QUOTES.length;
      return DAILY_COVER_QUOTES[quoteIndex];
    }

    function resolveCoverQuoteContent() {
      const rawQuote = String(coverSettingsState.quote || '').trim();
      const fallbackQuote = String(defaultCoverSettings.quote || '').trim();
      const useDaily = !rawQuote || rawQuote === fallbackQuote;
      const quote = useDaily ? getDailyCoverQuote() : rawQuote;
      const author = useDaily ? 'Daily motivation' : 'Custom motivation';
      return { quote, author };
    }

    function scheduleDailyCoverQuoteUpdate() {
      if (coverQuoteDailyTimer) {
        window.clearTimeout(coverQuoteDailyTimer);
        coverQuoteDailyTimer = null;
      }
      const now = new Date();
      const next = new Date(now);
      next.setHours(24, 0, 0, 0);
      const delay = Math.max(1000, next.getTime() - now.getTime() + 1500);
      coverQuoteDailyTimer = window.setTimeout(() => {
        applyCoverSettingsToUI();
        scheduleDailyCoverQuoteUpdate();
      }, delay);
    }

    function applyCoverSettingsToUI() {
      const profileName = document.getElementById('profileName');
      const coverLabel = document.querySelector('.cover-see-profile');
      const coverBadge = document.getElementById('coverGoalBadge');
      const quoteText = document.querySelector('#coverQuotePop .cover-quote-text');
      const quoteAuthor = document.querySelector('#coverQuotePop .cover-quote-author');
      const previewName = document.getElementById('coverPreviewName');
      const previewLabel = document.getElementById('coverPreviewLabel');
      const previewGoal = document.getElementById('coverPreviewGoal');
      const previewQuote = document.getElementById('coverPreviewQuote');

      const nextName = getEffectiveCoverName();
      const nextLabel = (coverSettingsState.headerLabel || 'Profile').trim() || 'Profile';
      const nextGoalBadge = (coverSettingsState.goalBadge || '@goal-smart').trim() || '@goal-smart';
      const quoteContent = resolveCoverQuoteContent();
      const nextQuote = quoteContent.quote;

      if (profileName) profileName.innerHTML = nextName.replace(/\s+/g, '<br>');
      if (coverLabel) coverLabel.textContent = nextLabel;
      if (coverBadge) coverBadge.textContent = nextGoalBadge;
      if (quoteText) quoteText.textContent = nextQuote;
      if (quoteAuthor) quoteAuthor.textContent = quoteContent.author;
      if (previewName) previewName.textContent = nextName;
      if (previewLabel) previewLabel.textContent = nextLabel;
      if (previewGoal) previewGoal.textContent = nextGoalBadge;
      if (previewQuote) previewQuote.textContent = nextQuote;
    }

