    function getSelectedGender() {
      const genderInput = document.getElementById('genderInput');
      const raw = String(genderInput?.value || profileState.gender || defaultProfile.gender || 'male').toLowerCase();
      if (raw === 'female') return 'female';
      return 'male';
    }

    function buildBodyTypeFigureSvg(gender = 'male', bodyType = 'mesomorph') {
      const isFemale = gender === 'female';
      const proportions = {
        ectomorph: { shoulder: 0.86, torso: 0.82, hip: 0.84, leg: 1.02 },
        mesomorph: { shoulder: 1.02, torso: 1.0, hip: 0.96, leg: 1.0 },
        endomorph: { shoulder: 1.06, torso: 1.16, hip: 1.12, leg: 0.96 }
      };
      const p = proportions[bodyType] || proportions.mesomorph;
      const baseX = 46;
      const shoulderW = (isFemale ? 21 : 24) * p.shoulder;
      const torsoW = (isFemale ? 17 : 19) * p.torso;
      const hipW = (isFemale ? 18 : 20) * p.hip;
      const legH = (isFemale ? 28 : 31) * p.leg;
      const armTone = isFemale ? '#d7ecff' : '#c6e4ff';
      const coreTone = isFemale ? '#9fd8ff' : '#8fcfff';
      const hipTone = isFemale ? '#abdfff' : '#98d3ff';
      return `
<svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 92 110">
  <defs>
    <linearGradient id="g${gender}${bodyType}" x1="0" y1="0" x2="0.9" y2="1">
      <stop offset="0%" stop-color="#071322"/>
      <stop offset="54%" stop-color="#0c2642"/>
      <stop offset="100%" stop-color="#0e3a5f"/>
    </linearGradient>
  </defs>
  <rect x="1" y="1" width="90" height="108" rx="16" fill="url(#g${gender}${bodyType})" stroke="rgba(180,220,255,0.34)" />
  <ellipse cx="46" cy="17" rx="${isFemale ? 9 : 10}" ry="${isFemale ? 8.2 : 9}" fill="#e8f5ff"/>
  <rect x="${baseX - shoulderW / 2}" y="27" width="${shoulderW}" height="${isFemale ? 11.5 : 12.5}" rx="6" fill="${armTone}"/>
  <rect x="${baseX - torsoW / 2}" y="38" width="${torsoW}" height="${isFemale ? 24 : 26}" rx="8" fill="${coreTone}"/>
  <rect x="${baseX - hipW / 2}" y="61" width="${hipW}" height="${isFemale ? 10 : 11}" rx="6" fill="${hipTone}"/>
  <rect x="${baseX - hipW / 2 - 5.8}" y="38" width="6" height="${isFemale ? 23 : 24}" rx="3" fill="${armTone}"/>
  <rect x="${baseX + hipW / 2 - 0.2}" y="38" width="6" height="${isFemale ? 23 : 24}" rx="3" fill="${armTone}"/>
  <rect x="${baseX - hipW / 2 + 2}" y="71" width="${isFemale ? 6.4 : 7.2}" height="${legH}" rx="4" fill="#c3e5ff"/>
  <rect x="${baseX + hipW / 2 - (isFemale ? 8.4 : 9.4)}" y="71" width="${isFemale ? 6.4 : 7.2}" height="${legH}" rx="4" fill="#c3e5ff"/>
  <ellipse cx="46" cy="102" rx="19" ry="4.6" fill="rgba(156,210,255,0.34)" />
</svg>`.trim();
    }

    function getBodyTypeImageDataUri(gender = 'male', bodyType = 'mesomorph') {
      return svgToDataUri(buildBodyTypeFigureSvg(gender, bodyType));
    }

    function applyBodyTypeImagesForGender(gender = 'male') {
      const normalizedGender = gender === 'female' ? 'female' : 'male';
      document.querySelectorAll('.bodytype-chip').forEach(chip => {
        const type = chip.dataset.bodyType || 'mesomorph';
        const img = chip.querySelector('.bodytype-photo');
        if (!img) return;
        const dataUri = getBodyTypeImageDataUri(normalizedGender, type);
        img.src = dataUri;
        const genderLabel = normalizedGender === 'female' ? 'female' : 'male';
        img.alt = `${type} body type (${genderLabel})`;
      });
      document.querySelectorAll('.bodytype-option').forEach(option => {
        const type = option.dataset.bodytypeOption || 'mesomorph';
        const img = option.querySelector('.gender-option-photo');
        if (!img) return;
        const dataUri = getBodyTypeImageDataUri(normalizedGender, type);
        img.src = dataUri;
        const genderLabel = normalizedGender === 'female' ? 'female' : 'male';
        img.alt = `${type} body type (${genderLabel})`;
      });
    }

