    function svgToDataUri(svgMarkup) {
      return `data:image/svg+xml;utf8,${encodeURIComponent(svgMarkup)}`;
    }

    function resolveExercisePose(exerciseName) {
      const label = (exerciseName || '').toLowerCase();
      if (/jumping jack|star jump/.test(label)) return 'jump';
      if (/high knee|march/.test(label)) return 'march';
      if (/step touch|side leg/.test(label)) return 'side-step';
      if (/squat|wall sit|chair squat|lunge|step-up/.test(label)) return 'squat';
      if (/push-up|plank up-down/.test(label)) return 'push';
      if (/plank/.test(label)) return 'plank';
      if (/bridge/.test(label)) return 'bridge';
      if (/crunch|bicycle|torso twist|russian twist|seated knee raise|seated leg lift/.test(label)) return 'core';
      if (/bird dog/.test(label)) return 'bird-dog';
      if (/calf raise|arm circle/.test(label)) return 'raise';
      return 'stand';
    }

