    function getExerciseDiagramImage(exerciseName) {
      return buildPoseSvg(resolveExercisePose(exerciseName));
    }

    function clampNumber(value, min, max, fallback) {
      const numeric = Number(value);
      if (!Number.isFinite(numeric)) return fallback;
      return Math.min(max, Math.max(min, numeric));
    }

    function deriveAdaptivePlanSettings(category, age, bodyType, goalWeeks, gender = 'male') {
      const normalizedAge = clampNumber(age, 10, 90, 28);
      const normalizedWeeks = clampNumber(goalWeeks, 1, 24, 6);
      const normalizedBodyType = ['ectomorph', 'mesomorph', 'endomorph'].includes(bodyType) ? bodyType : 'mesomorph';
      const normalizedGender = gender === 'female' ? 'female' : 'male';
      const categoryBase = {
        Underweight: 3,
        Normal: 4,
        Overweight: 5,
        Obese: 4,
        Smart: 4
      };
      const bodyTypeOffset = {
        ectomorph: 0,
        mesomorph: 1,
        endomorph: -1
      };
      const genderSessionOffset = {
        male: 0,
        female: -1
      };
      let sessionsPerWeek = categoryBase[category] || categoryBase.Smart;
      sessionsPerWeek += bodyTypeOffset[normalizedBodyType] || 0;
      sessionsPerWeek += genderSessionOffset[normalizedGender] || 0;
      if (normalizedAge >= 55) sessionsPerWeek -= 1;
      if (normalizedAge <= 24) sessionsPerWeek += 1;
      sessionsPerWeek = Math.min(6, Math.max(2, sessionsPerWeek));
      const targetSessions = sessionsPerWeek * normalizedWeeks;
      const intensityBase = {
        Underweight: 1.08,
        Normal: 1,
        Overweight: 0.96,
        Obese: 0.9,
        Smart: 1
      };
      let intensityScale = intensityBase[category] || intensityBase.Smart;
      if (normalizedBodyType === 'ectomorph') intensityScale += 0.04;
      if (normalizedBodyType === 'endomorph') intensityScale -= 0.04;
      if (normalizedAge >= 50) intensityScale -= 0.08;
      if (normalizedGender === 'female') intensityScale -= 0.03;
      intensityScale = Math.max(0.78, Math.min(1.22, intensityScale));
      return {
        weeks: normalizedWeeks,
        sessionsPerWeek,
        targetSessions,
        bodyType: normalizedBodyType,
        age: normalizedAge,
        gender: normalizedGender,
        intensityScale
      };
    }

    function adjustExercisePrescription(exercise, settings) {
      const source = exercise || {};
      const intensity = settings?.intensityScale || 1;
      const setsValue = clampNumber(parseInt(source.sets, 10), 1, 8, 3);
      const repsText = String(source.reps || '').trim();
      const repsNumber = parseInt(repsText, 10);
      let nextSets = Math.max(2, Math.min(6, Math.round(setsValue * intensity)));
      let nextRepsText = repsText;
      if (Number.isFinite(repsNumber)) {
        const nextReps = Math.max(6, Math.min(24, Math.round(repsNumber * intensity)));
        nextRepsText = repsText.toLowerCase().includes('sec') ? `${nextReps} sec` : `${nextReps}`;
      }
      return {
        ...source,
        sets: String(nextSets),
        reps: nextRepsText
      };
    }

    function buildAdaptivePlan(category, settings) {
      const basePlan = planSets[category] || planSets.Normal || [];
      if (basePlan.length === 0) return [];
      const generated = [];
      for (let index = 0; index < settings.targetSessions; index += 1) {
        const template = basePlan[index % basePlan.length];
        const weekNumber = Math.floor(index / settings.sessionsPerWeek) + 1;
        const sessionNumber = (index % settings.sessionsPerWeek) + 1;
        generated.push({
          title: `Week ${weekNumber} Day ${sessionNumber}`,
          focus: template.focus,
          exercises: (template.exercises || []).map(exercise => adjustExercisePrescription(exercise, settings))
        });
      }
      return generated;
    }

    function groupPlanByWeek(plan) {
      const weeks = [];
      const weekMap = new Map();
      (plan || []).forEach(day => {
        const weekMatch = /Week\s+(\d+)/i.exec(day.title || '');
        const weekLabel = weekMatch ? `Week ${weekMatch[1]}` : 'Week 1';
        if (!weekMap.has(weekLabel)) {
          const group = { label: weekLabel, days: [] };
          weekMap.set(weekLabel, group);
          weeks.push(group);
        }
        weekMap.get(weekLabel).days.push(day);
      });
      return weeks;
    }

    function updateHardwareTrackingUI() {
      const motionStatusText = document.getElementById('motionStatusText');
      const motionCountText = document.getElementById('motionCountText');
      if (motionStatusText) {
        motionStatusText.textContent = motionState.enabled
          ? 'Motion sensor: active'
          : (motionState.permission === 'denied' ? 'Motion sensor: permission denied' : 'Motion sensor: off');
      }
      if (motionCountText) {
        motionCountText.textContent = `${progressState.hardwareActivityCount || 0} live activity pulses`;
      }
      refreshOverlayRows();
    }

    function onDeviceMotion(event) {
      if (!motionState.enabled) return;
      const acc = event.accelerationIncludingGravity || event.acceleration;
      if (!acc) return;
      const magnitude = Math.abs(acc.x || 0) + Math.abs(acc.y || 0) + Math.abs(acc.z || 0);
      const now = Date.now();
      if (magnitude > 18 && (now - motionState.lastPulseAt) > 14000) {
        motionState.lastPulseAt = now;
        progressState.hardwareActivityCount = (progressState.hardwareActivityCount || 0) + 1;
        recordLiveActivity();
        handleOverlayMotionPulse();
        saveProgress();
        updateActivityTracker();
      }
    }

    async function enableMotionTracking() {
      try {
        if (!('DeviceMotionEvent' in window)) {
          motionState.permission = 'denied';
          updateHardwareTrackingUI();
          return;
        }
        if (typeof DeviceMotionEvent.requestPermission === 'function') {
          const permission = await DeviceMotionEvent.requestPermission();
          motionState.permission = permission === 'granted' ? 'granted' : 'denied';
          if (permission !== 'granted') {
            motionState.enabled = false;
            updateHardwareTrackingUI();
            return;
          }
        } else {
          motionState.permission = 'granted';
        }
        if (!motionState.enabled) {
          window.addEventListener('devicemotion', onDeviceMotion, { passive: true });
        }
        motionState.enabled = true;
        updateHardwareTrackingUI();
      } catch (_error) {
        motionState.permission = 'denied';
        motionState.enabled = false;
        updateHardwareTrackingUI();
      }
    }

    function toLocalDateKey(dateObj = new Date()) {
      const year = dateObj.getFullYear();
      const month = String(dateObj.getMonth() + 1).padStart(2, '0');
      const day = String(dateObj.getDate()).padStart(2, '0');
      return `${year}-${month}-${day}`;
    }

    function dateKeyShift(dateKey, dayDelta) {
      const shifted = new Date(`${dateKey}T12:00:00`);
      shifted.setDate(shifted.getDate() + dayDelta);
      return toLocalDateKey(shifted);
    }

    function recordLiveActivity() {
      const todayKey = toLocalDateKey();
      progressState.dailyActivity[todayKey] = (progressState.dailyActivity[todayKey] || 0) + 1;
      progressState.lastActivityAt = Date.now();
    }

    function computeDailyStreak() {
      let streak = 0;
      let cursor = toLocalDateKey();
      while ((progressState.dailyActivity[cursor] || 0) > 0) {
        streak += 1;
        cursor = dateKeyShift(cursor, -1);
      }
      return streak;
    }

    function countTrackedActiveDays() {
      const activityMap = progressState?.dailyActivity || {};
      return Object.values(activityMap).reduce((count, value) => {
        return count + ((Number(value) || 0) > 0 ? 1 : 0);
      }, 0);
    }

    function getLatestActivityLabel() {
      if (!progressState.lastActivityAt) return 'No workout completed yet.';
      const latest = new Date(progressState.lastActivityAt);
      const latestKey = toLocalDateKey(latest);
      const todayKey = toLocalDateKey();
      const yesterdayKey = dateKeyShift(todayKey, -1);
      if (latestKey === todayKey) return 'Latest completed: Today';
      if (latestKey === yesterdayKey) return 'Latest completed: Yesterday';
      return `Latest completed: ${latest.toLocaleDateString(undefined, { month: 'short', day: 'numeric' })}`;
    }

    function estimateCalorieInsights(completedMoves, totalMoves, completedDays, totalDays) {
      const weightInput = document.getElementById('weightInput');
      const bodyTypeInput = document.getElementById('bodyTypeInput');
      const weight = clampNumber(weightInput?.value, 35, 250, 70);
      const bodyType = bodyTypeInput?.value || 'mesomorph';
      const categoryFactor = {
        Underweight: 4.7,
        Normal: 5.8,
        Overweight: 5.2,
        Obese: 4.6,
        Smart: 5.1
      };
      const bodyTypeFactor = {
        ectomorph: 0.95,
        mesomorph: 1,
        endomorph: 0.92
      };
      const completionRatio = totalMoves > 0 ? completedMoves / totalMoves : 0;
      const avgMinutesPerMove = motionState.enabled ? 1.7 : 1.35;
      const estimatedMinutes = Math.max(0, (completedMoves * avgMinutesPerMove) + (progressState.hardwareActivityCount * 0.08));
      const met = (categoryFactor[lastCategory] || categoryFactor.Smart) * (bodyTypeFactor[bodyType] || 1) * (1 + completionRatio * 0.18);
      const calories = Math.max(0, Math.round((met * 3.5 * weight / 200) * estimatedMinutes));
      const targetMinutes = Math.max(12, totalMoves * 1.45);
      const targetCalories = Math.max(180, Math.round((met * 3.5 * weight / 200) * targetMinutes));
      const caloriePercent = Math.min(100, Math.round((calories / targetCalories) * 100));
      const kgLoss = calories / 7700;
      const lbsLoss = kgLoss * 2.20462;
      const sessionRate = totalDays > 0 ? Math.round((completedDays / totalDays) * 100) : 0;
      return {
        calories,
        kgLoss,
        lbsLoss,
        caloriePercent,
        sessionRate
      };
    }

    function computeExerciseTrackMetrics(plan) {
      const tracks = [
        {
          key: 'A',
          fallbackTitle: 'Strength',
          fallbackMeta: 'Leg drive and endurance',
          matcher: /squat|lunge|calf|step-up|wall sit|bridge|dip/i
        },
        {
          key: 'B',
          fallbackTitle: 'Cardio',
          fallbackMeta: 'Cardio pacing',
          matcher: /jog|run|jumping jack|mountain climber|high knee|march|step touch|burpee/i
        },
        {
          key: 'C',
          fallbackTitle: 'Core',
          fallbackMeta: 'Core stability',
          matcher: /plank|crunch|twist|leg raise|knee raise|superman|bird dog|sit-up/i
        }
      ];

      const result = {};
      tracks.forEach(track => {
        let total = 0;
        let done = 0;
        const nameCounter = new Map();
        (plan || []).forEach(day => {
          (day.exercises || []).forEach(exercise => {
            const name = String(exercise?.name || '');
            if (!track.matcher.test(name)) return;
            total += 1;
            const counter = nameCounter.get(name) || { total: 0, done: 0 };
            counter.total += 1;
            if (progressState.completedExercises[workoutExerciseKey(day.title, name)]) {
              done += 1;
              counter.done += 1;
            }
            nameCounter.set(name, counter);
          });
        });

        let representative = '';
        let score = -1;
        nameCounter.forEach((counts, name) => {
          const nextScore = counts.done * 100 + counts.total;
          if (nextScore > score) {
            score = nextScore;
            representative = name;
          }
        });

        result[track.key] = {
          title: representative || track.fallbackTitle,
          meta: total > 0 ? `${done}/${total} moves completed` : track.fallbackMeta,
          percent: total > 0 ? Math.round((done / total) * 100) : 0
        };
      });
      return result;
    }

    function updateActivityTracker() {
      const activityCompletedMoves = document.getElementById('activityCompletedMoves');
      const activityTotalMoves = document.getElementById('activityTotalMoves');
      const activityCompletedDays = document.getElementById('activityCompletedDays');
      const activityTotalDays = document.getElementById('activityTotalDays');
      const activityPercent = document.getElementById('activityPercent');
      const activityLastWorkout = document.getElementById('activityLastWorkout');
      const heroPlanValue = document.getElementById('heroPlanValue');
      const heroProgressValue = document.getElementById('heroBmiValue');
      const heroProgressNote = document.getElementById('heroBmiNote');
      const heroTrackingType = document.getElementById('heroTrackingType');
      const taglineText = document.getElementById('taglineText');

      const totalMoves = currentPlan.reduce((sum, day) => sum + day.exercises.length, 0);
      const totalDays = currentPlan.length;

      const completedMoves = currentPlan.reduce((sum, day) => {
        return sum + day.exercises.filter(ex => progressState.completedExercises[workoutExerciseKey(day.title, ex.name)]).length;
      }, 0);

      const completedDays = currentPlan.reduce((sum, day) => {
        const dayDone = day.exercises.length > 0 && day.exercises.every(ex => progressState.completedExercises[workoutExerciseKey(day.title, ex.name)]);
        return sum + (dayDone ? 1 : 0);
      }, 0);

      const percent = totalMoves > 0 ? Math.round((completedMoves / totalMoves) * 100) : 0;
      const streak = computeDailyStreak();
      const latestLabel = getLatestActivityLabel();
      const remainingMoves = Math.max(0, totalMoves - completedMoves);
      const metrics = estimateCalorieInsights(completedMoves, totalMoves, completedDays, totalDays);

      if (activityCompletedMoves) activityCompletedMoves.textContent = `${completedMoves}`;
      if (activityTotalMoves) activityTotalMoves.textContent = `${totalMoves}`;
      if (activityCompletedDays) activityCompletedDays.textContent = `${completedDays}`;
      if (activityTotalDays) activityTotalDays.textContent = `${totalDays}`;
      if (activityPercent) activityPercent.textContent = `${percent}%`;
      if (activityLastWorkout) activityLastWorkout.textContent = latestLabel;
      if (heroPlanValue) heroPlanValue.textContent = `${streak} day${streak === 1 ? '' : 's'}`;
      if (heroProgressValue) heroProgressValue.textContent = `${percent}%`;
      if (heroProgressNote) heroProgressNote.textContent = `${completedMoves}/${totalMoves || 0} moves`;
      if (heroTrackingType) heroTrackingType.textContent = motionState.enabled ? 'Live tracking + motion' : (streak > 0 ? 'Live tracking' : 'Tracking ready');
      if (taglineText) {
        taglineText.textContent = totalMoves > 0
          ? `Goal plan: ${currentPlanMeta.weeks} week${currentPlanMeta.weeks === 1 ? '' : 's'} / ${currentPlanMeta.targetSessions} sessions. ${remainingMoves} moves remaining to target.`
          : 'Enter stats and calculate to start live tracking.';
      }
      const summaryTitle = document.getElementById('trackingSummaryTitle');
      const summaryText = document.getElementById('trackingSummaryText');
      const heroTrackStreak = document.getElementById('heroTrackStreak');
      const heroTrackCalories = document.getElementById('heroTrackCalories');
      const exerciseTitleA = document.getElementById('exerciseTitleA');
      const exerciseTitleB = document.getElementById('exerciseTitleB');
      const exerciseTitleC = document.getElementById('exerciseTitleC');
      const exerciseMetaA = document.getElementById('exerciseMetaA');
      const exerciseMetaB = document.getElementById('exerciseMetaB');
      const exerciseMetaC = document.getElementById('exerciseMetaC');
      const exerciseCardA = document.getElementById('exerciseCardA');
      const exerciseCardB = document.getElementById('exerciseCardB');
      const exerciseCardC = document.getElementById('exerciseCardC');
      const exercisePctA = document.getElementById('exercisePctA');
      const exercisePctB = document.getElementById('exercisePctB');
      const exercisePctC = document.getElementById('exercisePctC');
      const trackMetrics = computeExerciseTrackMetrics(currentPlan);
      if (summaryTitle) {
        summaryTitle.textContent = `${completedMoves} moves completed â€¢ ${streak} day${streak === 1 ? '' : 's'} streak`;
      }
      if (summaryText) {
        summaryText.textContent = `Estimated ${metrics.calories} kcal burnt (${metrics.kgLoss.toFixed(2)} kg / ${metrics.lbsLoss.toFixed(2)} lb). Session completion ${metrics.sessionRate}%, with ${remainingMoves} moves left to hit your current goal.`;
      }
      if (heroTrackStreak) heroTrackStreak.textContent = `${streak} day${streak === 1 ? '' : 's'}`;
      if (heroTrackCalories) heroTrackCalories.textContent = `${metrics.calories} kcal`;
      if (exerciseTitleA) exerciseTitleA.textContent = trackMetrics.A.title;
      if (exerciseTitleB) exerciseTitleB.textContent = trackMetrics.B.title;
      if (exerciseTitleC) exerciseTitleC.textContent = trackMetrics.C.title;
      if (exerciseMetaA) exerciseMetaA.textContent = trackMetrics.A.meta;
      if (exerciseMetaB) exerciseMetaB.textContent = trackMetrics.B.meta;
      if (exerciseMetaC) exerciseMetaC.textContent = trackMetrics.C.meta;
      if (exercisePctA) exercisePctA.textContent = `${trackMetrics.A.percent}%`;
      if (exercisePctB) exercisePctB.textContent = `${trackMetrics.B.percent}%`;
      if (exercisePctC) exercisePctC.textContent = `${trackMetrics.C.percent}%`;
      if (exerciseCardA) exerciseCardA.classList.toggle('active-progress', trackMetrics.A.percent > 0);
      if (exerciseCardB) exerciseCardB.classList.toggle('active-progress', trackMetrics.B.percent > 0);
      if (exerciseCardC) exerciseCardC.classList.toggle('active-progress', trackMetrics.C.percent > 0);
      if (exerciseCardA) exerciseCardA.style.setProperty('--exercise-progress', String(Math.max(0, Math.min(100, trackMetrics.A.percent))));
      if (exerciseCardB) exerciseCardB.style.setProperty('--exercise-progress', String(Math.max(0, Math.min(100, trackMetrics.B.percent))));
      if (exerciseCardC) exerciseCardC.style.setProperty('--exercise-progress', String(Math.max(0, Math.min(100, trackMetrics.C.percent))));

      const progressRing = document.getElementById('progressRing');
      const progressRingValue = document.getElementById('progressRingValue');
      const calorieRing = document.getElementById('calorieRing');
      const calorieRingValue = document.getElementById('calorieRingValue');
      const weightRing = document.getElementById('weightRing');
      const weightRingValue = document.getElementById('weightRingValue');
      if (progressRing) progressRing.style.setProperty('--percent', `${Math.max(0, Math.min(100, percent))}`);
      if (progressRingValue) progressRingValue.textContent = `${percent}%`;
      if (calorieRing) calorieRing.style.setProperty('--percent', `${metrics.caloriePercent}`);
      if (calorieRingValue) calorieRingValue.textContent = `${metrics.calories}`;
      const weightPct = Math.max(0, Math.min(100, Math.round((metrics.kgLoss / 3) * 100)));
      if (weightRing) weightRing.style.setProperty('--percent', `${weightPct}`);
      if (weightRingValue) weightRingValue.textContent = `${metrics.kgLoss.toFixed(2)}kg`;

      updateMqPanel(percent, metrics);
      updateHardwareTrackingUI();
    }

    function updateMqScaleFromData(valuesMap) {
      const numericValues = Object.values(valuesMap || {}).map(value => Number(value) || 0).filter(value => value > 0);
      const averageMq = numericValues.length
        ? Math.round(numericValues.reduce((sum, value) => sum + value, 0) / numericValues.length)
        : 0;
      const tiers = [
        { key: 'sculpted', label: 'Sculpted', min: 144, pos: 8, color: 'rgba(160, 233, 255, 0.95)' },
        { key: 'athletic', label: 'Athletic', min: 136, pos: 28, color: 'rgba(112, 214, 255, 0.95)' },
        { key: 'fit', label: 'Fit', min: 130, pos: 50, color: 'rgba(142, 217, 102, 0.95)' },
        { key: 'average', label: 'Average', min: 124, pos: 71, color: 'rgba(226, 214, 95, 0.95)' },
        { key: 'needs-work', label: 'Needs Work', min: -999, pos: 90, color: 'rgba(255, 182, 92, 0.95)' }
      ];
      const activeTier = tiers.find(tier => averageMq >= tier.min) || tiers[tiers.length - 1];
      const marker = document.getElementById('mqScaleMarker');
      const status = document.getElementById('mqScaleStatus');
      const score = document.getElementById('mqScaleScore');
      const labelNodes = document.querySelectorAll('.mq-scale-labels [data-level]');

      if (marker) {
        marker.style.top = `${activeTier.pos}%`;
        marker.style.background = activeTier.color;
        marker.style.boxShadow = `0 0 0 3px rgba(18, 30, 48, 0.72), 0 0 12px ${activeTier.color}`;
      }
      labelNodes.forEach(node => {
        node.classList.toggle('active', node.dataset.level === activeTier.key);
      });
      if (status) {
        status.textContent = `Current level: ${activeTier.label} - ${averageMq} MQ avg`;
      }
      if (score) {
        score.textContent = `${averageMq} MQ`;
      }
    }

    function updateMqPanel(percent, metrics = null) {
      const baseMap = {
        Underweight: 128,
        Normal: 138,
        Overweight: 132,
        Obese: 125,
        Smart: 130
      };
      const genderBias = getSelectedGender() === 'female' ? -2 : 0;
      const base = baseMap[lastCategory] || baseMap.Smart;
      const lift = Math.round((percent || 0) * 0.14);
      const trackMix = computeExerciseTrackMetrics(currentPlan);
      const strengthBoost = Math.round((trackMix.A?.percent || 0) * 0.08);
      const cardioBoost = Math.round((trackMix.B?.percent || 0) * 0.06);
      const coreBoost = Math.round((trackMix.C?.percent || 0) * 0.1);
      const values = {
        mqShoulderL: base + lift - 2 + genderBias + Math.round(strengthBoost * 0.7),
        mqChestL: base + lift + 3 + Math.round(strengthBoost * 0.8),
        mqBicepsL: base + lift + 1 + genderBias + Math.round(strengthBoost * 0.9),
        mqAbsL: base + lift + 5 + coreBoost + Math.round(cardioBoost * 0.3),
        mqForearmL: base + lift - 4 + genderBias + Math.round(strengthBoost * 0.45),
        mqQuadL: base + lift + 7 + Math.round(strengthBoost * 0.6) + cardioBoost,
        mqShoulderR: base + lift + 1 + genderBias + Math.round(strengthBoost * 0.72),
        mqChestR: base + lift + 4 + Math.round(strengthBoost * 0.82),
        mqBicepsR: base + lift + 1 + genderBias + Math.round(strengthBoost * 0.88),
        mqAbsR: base + lift + 6 + coreBoost + Math.round(cardioBoost * 0.3),
        mqForearmR: base + lift - 5 + genderBias + Math.round(strengthBoost * 0.46),
        mqQuadR: base + lift + 4 + Math.round(strengthBoost * 0.6) + cardioBoost
      };
      Object.keys(values).forEach(id => {
        const node = document.getElementById(id);
        if (node) node.textContent = `${values[id]}`;
      });
      const leftAverage = Math.round((values.mqShoulderL + values.mqChestL + values.mqBicepsL + values.mqAbsL + values.mqForearmL + values.mqQuadL) / 6);
      const rightAverage = Math.round((values.mqShoulderR + values.mqChestR + values.mqBicepsR + values.mqAbsR + values.mqForearmR + values.mqQuadR) / 6);
      const balanceNode = document.getElementById('mqSideBalance');
      if (balanceNode) {
        const delta = Math.abs(leftAverage - rightAverage);
        balanceNode.textContent = `L/R balance ${leftAverage}/${rightAverage}${delta > 0 ? ` | Delta ${delta}` : ''}`;
      }
      updateMqScaleFromData(values);
      updateTrackingBodyGraphic();
      const mqTitle = document.getElementById('mqTitle');
      if (mqTitle) {
        const firstName = getFirstName(profileState.name);
        mqTitle.innerHTML = `${firstName}'s <span class="mq-highlight">MQ (Muscle Quality)</span>`;
      }
      const activityLastWorkout = document.getElementById('activityLastWorkout');
      if (activityLastWorkout && metrics) {
        activityLastWorkout.textContent = `${getLatestActivityLabel()} - ${metrics.calories} kcal`;
      }
    }

    function showPage(pageName, immediate = false) {
      const nextPage = document.querySelector(`.app-page[data-page="${pageName}"]`);
      if (!nextPage) return;
      if (pageTransitionLock && !immediate) return;

      const currentPage = document.querySelector('.app-page.active');
      const currentPageName = currentPage?.dataset?.page || '';
      document.body.dataset.currentPage = pageName;
      if (pageName !== 'tracking') {
        setMqSubmenuOpen(false);
      }
      if (pageName === 'nutrition') {
        if (!nutritionState.currentPlan) regenerateNutritionPlan();
        setNutritionTab(nutritionState.activeTab || 'overview');
      }
      if (pageName === 'bmi') {
        syncGuidedSetupFlow();
        window.setTimeout(() => {
          if (document.body?.dataset?.currentPage === 'bmi') {
            focusSetupStep(guidedSetupState.currentIndex, false);
          }
        }, 20);
      }
      const activeNavTarget = pageName === 'plan' ? 'bmi' : pageName;
      document.querySelectorAll('.nav-item').forEach(item => {
        item.classList.toggle('active', item.dataset.pageTarget === activeNavTarget);
      });

      if (!currentPage || currentPage === nextPage || immediate) {
        document.querySelectorAll('.app-page').forEach(page => {
          page.classList.remove(
            'leaving',
            'enter-from-right',
            'enter-from-left',
            'leave-to-left',
            'leave-to-right'
          );
          page.classList.toggle('active', page === nextPage);
        });
        window.scrollTo({ top: 0, behavior: 'smooth' });
        return;
      }

      const direction = resolvePageDirection(currentPageName, pageName);
      const leaveClass = direction > 0 ? 'leave-to-left' : 'leave-to-right';
      const enterClass = direction > 0 ? 'enter-from-right' : 'enter-from-left';

      pageTransitionLock = true;
      currentPage.classList.remove('enter-from-right', 'enter-from-left', 'leave-to-left', 'leave-to-right');
      currentPage.classList.add('leaving', leaveClass);
      currentPage.classList.remove('active');

      nextPage.classList.remove('leaving', 'leave-to-left', 'leave-to-right', 'enter-from-right', 'enter-from-left');
      nextPage.classList.add('active', enterClass);

      window.setTimeout(() => {
        currentPage.classList.remove('leaving', leaveClass);
        nextPage.classList.remove(enterClass);
        pageTransitionLock = false;
      }, PAGE_TRANSITION_MS);

      window.scrollTo({ top: 0, behavior: 'smooth' });
    }

    function getCurrentPageName() {
      return document.querySelector('.app-page.active')?.dataset?.page || 'cover';
    }

    function navigateBySwipe(direction) {
      const currentPageName = getCurrentPageName();
      const currentIndex = PAGE_ORDER.indexOf(currentPageName);
      if (currentIndex === -1) return;
      const nextIndex = currentIndex + direction;
      if (nextIndex < 0 || nextIndex >= PAGE_ORDER.length) return;
      showPage(PAGE_ORDER[nextIndex]);
    }

    function shouldIgnoreSwipeTarget(target) {
      if (!(target instanceof Element)) return false;
      return Boolean(
        target.closest(
          'input, textarea, select, button, a, [role="button"], .activity-overlay.open, .activity-screen, .profile-edit-modal.open, .cover-menu.open'
        )
      );
    }

    function initPageSwipeNavigation() {
      const shell = document.querySelector('.app-shell');
      if (!shell) return;
      let startX = 0;
      let startY = 0;
      let startTime = 0;
      let canSwipe = false;
      let edgeSwipeStart = false;

      shell.addEventListener('touchstart', event => {
        if (!event.touches || event.touches.length !== 1) return;
        if (activityOverlayState.isOpen) return;
        const touch = event.touches[0];
        const edgeZone = 30;
        edgeSwipeStart = touch.clientX <= edgeZone || touch.clientX >= (window.innerWidth - edgeZone);
        const target = event.target;
        if (!edgeSwipeStart && shouldIgnoreSwipeTarget(target)) return;
        startX = touch.clientX;
        startY = touch.clientY;
        startTime = Date.now();
        canSwipe = true;
      }, { passive: true });

      shell.addEventListener('touchend', event => {
        if (!canSwipe || !event.changedTouches || event.changedTouches.length !== 1) return;
        canSwipe = false;
        const touch = event.changedTouches[0];
        const dx = touch.clientX - startX;
        const dy = touch.clientY - startY;
        const dt = Date.now() - startTime;
        const absX = Math.abs(dx);
        const absY = Math.abs(dy);
        const minDistance = edgeSwipeStart ? 36 : 56;
        const maxVerticalDrift = 72;
        const maxDuration = 780;
        if (dt > maxDuration) return;
        if (absX < minDistance) return;
        if (absY > maxVerticalDrift) return;
        if (absX < absY * 1.15) return;
        if (dx < 0) {
          navigateBySwipe(1);
        } else {
          navigateBySwipe(-1);
        }
      }, { passive: true });

      shell.addEventListener('touchcancel', () => {
        canSwipe = false;
        edgeSwipeStart = false;
      }, { passive: true });
    }

    const CODEX_AUTO_REFRESH_KEY = 'codex_auto_refresh_enabled_v1';
    const CODEX_AUTO_REFRESH_INTERVAL_MS = 18000;
    const CODEX_AUTO_REFRESH_IDLE_MS = 14000;
    let codexLastInteractionAt = Date.now();
    let codexAutoRefreshTimer = null;

    function trackCodexInteraction() {
      codexLastInteractionAt = Date.now();
    }

    function shouldPauseCodexAutoRefresh() {
      const profileModal = document.getElementById('profileEditModal');
      const coverEditModal = document.getElementById('coverEditModal');
      const appearanceModal = document.getElementById('appearanceModal');
      const coverMenu = document.getElementById('coverMenu');
      const hasFocus = typeof document.hasFocus === 'function' ? document.hasFocus() : true;
      return Boolean(
        hasFocus ||
        activityOverlayState.isOpen ||
        (profileModal && profileModal.classList.contains('open')) ||
        (coverEditModal && coverEditModal.classList.contains('open')) ||
        (appearanceModal && appearanceModal.classList.contains('open')) ||
        (coverMenu && coverMenu.classList.contains('open'))
      );
    }

    function initCodexAutoRefresh() {
      if (window.location.protocol !== 'file:') return;
      try {
        const saved = localStorage.getItem(CODEX_AUTO_REFRESH_KEY);
        if (saved === null) localStorage.setItem(CODEX_AUTO_REFRESH_KEY, '1');
      } catch (_error) {}
      let enabled = true;
      try {
        enabled = localStorage.getItem(CODEX_AUTO_REFRESH_KEY) !== '0';
      } catch (_error) {}
      if (!enabled) return;

      ['pointerdown', 'pointermove', 'keydown', 'touchstart', 'wheel', 'input', 'scroll'].forEach(eventName => {
        document.addEventListener(eventName, trackCodexInteraction, { passive: true });
      });
      document.addEventListener('visibilitychange', trackCodexInteraction, { passive: true });

      if (codexAutoRefreshTimer) window.clearInterval(codexAutoRefreshTimer);
      codexAutoRefreshTimer = window.setInterval(() => {
        if (document.hidden) return;
        if (shouldPauseCodexAutoRefresh()) return;
        const now = Date.now();
        if (now - codexLastInteractionAt < CODEX_AUTO_REFRESH_IDLE_MS) return;
        const nextUrl = new URL(window.location.href);
        nextUrl.searchParams.set('live', String(now));
        window.location.replace(nextUrl.toString());
      }, CODEX_AUTO_REFRESH_INTERVAL_MS);
    }

    function deriveAutoPulseTarget(exercise) {
      const repsText = String(exercise?.reps || '').toLowerCase();
      const setsCount = Math.max(1, parseInt(exercise?.sets, 10) || 1);
      const repsValue = Math.max(0, parseInt(repsText, 10) || 0);
      let target = 6;
      if (repsText.includes('sec')) {
        target = Math.max(4, Math.min(10, Math.round(repsValue / 10) + 2));
      } else if (repsValue > 0) {
        target = Math.max(4, Math.min(10, Math.round((repsValue * setsCount) / 18)));
      }
      return target;
    }

    function getPulseCountForExercise(exerciseKey) {
      return progressState.exercisePulseCounts?.[exerciseKey] || 0;
    }

    function setPulseCountForExercise(exerciseKey, count) {
      if (!progressState.exercisePulseCounts) progressState.exercisePulseCounts = {};
      progressState.exercisePulseCounts[exerciseKey] = Math.max(0, Math.round(count || 0));
    }

    function updateDayCompletionState(day) {
      if (!day?.exercises?.length) return false;
      const dayKey = workoutDayKey(day.title);
      const dayDone = day.exercises.every(item => progressState.completedExercises[workoutExerciseKey(day.title, item.name)]);
      if (dayDone) {
        progressState.completedDays[dayKey] = true;
      } else {
        delete progressState.completedDays[dayKey];
      }
      return dayDone;
    }

    function updateSessionRowVisual(row) {
      if (!row) return;
      const key = row.dataset.exerciseKey;
      const target = Number(row.dataset.pulseTarget || 6);
      const progressLabel = row.querySelector('.session-progress');
      const checkIcon = row.querySelector('.session-check-icon');
      const done = !!progressState.completedExercises[key];
      const pulseCount = Math.min(target, getPulseCountForExercise(key));
      row.classList.toggle('completed', done);
      row.classList.toggle('active', activityOverlayState.activeExerciseKey === key);
      if (progressLabel) {
        if (done) {
          progressLabel.textContent = 'Done';
        } else if (motionState.enabled) {
          progressLabel.textContent = `${pulseCount}/${target} pulses`;
        } else {
          progressLabel.textContent = 'Tap to mark complete';
        }
      }
      if (checkIcon) {
        checkIcon.innerHTML = done ? '&#10003;' : '&#9675;';
      }
    }

    function refreshOverlayRows() {
      const list = document.getElementById('sessionList');
      if (!list) return;
      list.querySelectorAll('.session-row').forEach(updateSessionRowVisual);
    }

    function setExerciseCompletion(day, exercise, shouldComplete, options = {}) {
      if (!day || !exercise) return false;
      const {
        recordActivity = false,
        rerender = true
      } = options;
      const key = workoutExerciseKey(day.title, exercise.name);
      const target = deriveAutoPulseTarget(exercise);
      const currentlyDone = !!progressState.completedExercises[key];
      const nextDone = !!shouldComplete;
      if (currentlyDone === nextDone) return false;
      if (nextDone) {
        progressState.completedExercises[key] = true;
        setPulseCountForExercise(key, target);
        if (recordActivity) recordLiveActivity();
      } else {
        delete progressState.completedExercises[key];
        setPulseCountForExercise(key, 0);
      }
      updateDayCompletionState(day);
      saveProgress();
      updateActivityTracker();
      updateProfileStats(lastBmi, lastCategory);
      if (rerender) renderPlan(currentPlan, { keepPage: true });
      refreshOverlayRows();
      return true;
    }

    function setActivityPreview(exercise, stepIndex, totalSteps) {
      const preview = document.getElementById('activityPreviewImage');
      const caption = document.getElementById('activityPreviewCaption');
      const counter = document.getElementById('activityStepCounter');
      if (!exercise || !preview || !caption || !counter) return;
      preview.src = getExerciseDiagramImage(exercise.name);
      preview.alt = exercise.name;
      caption.textContent = `${exercise.name} - ${exercise.sets} sets - ${exercise.reps}`;
      counter.textContent = `${stepIndex + 1} / ${totalSteps}`;
    }

    function setActiveOverlayExercise(day, exercise, index, totalExercises) {
      if (!day || !exercise) return;
      const key = workoutExerciseKey(day.title, exercise.name);
      activityOverlayState.activeExerciseKey = key;
      activityOverlayState.activeExerciseIndex = index;
      setActivityPreview(exercise, index, totalExercises);
      refreshOverlayRows();
    }

    function autoAdvanceOverlayExercise(totalExercises) {
      const list = document.getElementById('sessionList');
      if (!list) return;
      const rows = Array.from(list.querySelectorAll('.session-row'));
      if (!rows.length) return;
      const start = activityOverlayState.activeExerciseIndex || 0;
      for (let idx = start + 1; idx < rows.length; idx += 1) {
        const row = rows[idx];
        if (!progressState.completedExercises[row.dataset.exerciseKey]) {
          row.querySelector('.session-main')?.click();
          return;
        }
      }
      for (let idx = 0; idx <= start; idx += 1) {
        const row = rows[idx];
        if (!progressState.completedExercises[row.dataset.exerciseKey]) {
          row.querySelector('.session-main')?.click();
          return;
        }
      }
      if (rows[Math.min(rows.length - 1, start)]) {
        rows[Math.min(rows.length - 1, start)].querySelector('.session-main')?.click();
      }
    }

    function handleOverlayMotionPulse() {
      if (!activityOverlayState.isOpen || !motionState.enabled || !activityOverlayState.day) return;
      const activeKey = activityOverlayState.activeExerciseKey;
      if (!activeKey || progressState.completedExercises[activeKey]) return;
      const exercise = activityOverlayState.exerciseByKey[activeKey];
      if (!exercise) return;
      const target = deriveAutoPulseTarget(exercise);
      const nextCount = getPulseCountForExercise(activeKey) + 1;
      setPulseCountForExercise(activeKey, Math.min(target, nextCount));
      if (nextCount >= target) {
        setExerciseCompletion(activityOverlayState.day, exercise, true, { recordActivity: false, rerender: true });
        autoAdvanceOverlayExercise(activityOverlayState.day.exercises.length);
      } else {
        saveProgress();
        refreshOverlayRows();
      }
    }

    function openActivityFromDayCard(dayCard, day) {
      if (!dayCard || !day || dayCard.dataset.opening === '1') return;
      dayCard.dataset.opening = '1';
      dayCard.classList.remove('opening');
      // Restart the opening pulse animation each tap.
      void dayCard.offsetWidth;
      dayCard.classList.add('opening');
      window.setTimeout(() => {
        openActivity(day);
        dayCard.classList.remove('opening');
        dayCard.dataset.opening = '0';
      }, 170);
    }

    function openActivity(day) {
      const overlay = document.getElementById('activityOverlay');
      const title = document.getElementById('activityTitle');
      const focus = document.getElementById('activityFocus');
      const list = document.getElementById('sessionList');
      const activityScreen = overlay?.querySelector('.activity-screen');
      if (!overlay || !day) return;

      const firstExercise = day.exercises[0];
      overlay.classList.remove('closing');
      activityOverlayState.isOpen = true;
      activityOverlayState.day = day;
      activityOverlayState.exerciseByKey = {};
      activityOverlayState.activeExerciseIndex = 0;
      activityOverlayState.activeExerciseKey = '';
      title.textContent = day.title;
      focus.textContent = day.focus;
      list.innerHTML = '';
      day.exercises.forEach((ex, index) => {
        const row = document.createElement('div');
        row.className = 'session-row';
        const exKey = workoutExerciseKey(day.title, ex.name);
        const pulseTarget = deriveAutoPulseTarget(ex);
        row.dataset.exerciseKey = exKey;
        row.dataset.pulseTarget = String(pulseTarget);
        activityOverlayState.exerciseByKey[exKey] = ex;

        const main = document.createElement('div');
        main.className = 'session-main';
        main.setAttribute('role', 'button');
        main.setAttribute('tabindex', '0');

        const img = document.createElement('img');
        img.src = getExerciseDiagramImage(ex.name);
        img.alt = ex.name;

        const textWrap = document.createElement('div');
        textWrap.className = 'session-copy';
        textWrap.innerHTML = `<strong>${ex.name}</strong><span class="session-meta">${ex.sets} sets - ${ex.reps}</span><span class="session-progress"></span>`;

        const checkBtn = document.createElement('button');
        checkBtn.type = 'button';
        checkBtn.className = 'session-check';
        checkBtn.setAttribute('aria-label', `Mark ${ex.name} as done`);
        checkBtn.innerHTML = '<span class="session-check-icon" aria-hidden="true">&#9675;</span>';

        main.appendChild(img);
        main.appendChild(textWrap);
        row.appendChild(main);
        row.appendChild(checkBtn);

        const activateExercise = () => {
          setActiveOverlayExercise(day, ex, index, day.exercises.length);
        };

        main.addEventListener('click', activateExercise);
        main.addEventListener('keydown', (event) => {
          if (event.key === 'Enter' || event.key === ' ') {
            event.preventDefault();
            activateExercise();
          }
        });

        checkBtn.addEventListener('click', (event) => {
          event.stopPropagation();
          const done = !!progressState.completedExercises[exKey];
          setExerciseCompletion(day, ex, !done, { recordActivity: !done, rerender: true });
          if (!done) {
            activateExercise();
            autoAdvanceOverlayExercise(day.exercises.length);
          }
        });
        list.appendChild(row);
        updateSessionRowVisual(row);
      });
      const rows = Array.from(list.querySelectorAll('.session-row'));
      const firstPendingRow = rows.find(row => !progressState.completedExercises[row.dataset.exerciseKey]) || rows[0];
      if (firstPendingRow) {
        const pendingIndex = rows.indexOf(firstPendingRow);
        const pendingExercise = day.exercises[pendingIndex] || firstExercise;
        setActiveOverlayExercise(day, pendingExercise, Math.max(0, pendingIndex), day.exercises.length);
      } else {
        setActivityPreview(firstExercise, 0, day.exercises.length);
      }
      if (activityScreen) activityScreen.scrollTop = 0;
      overlay.classList.add('open');
      overlay.setAttribute('aria-hidden', 'false');
      document.body.classList.add('activity-page-open');
    }

    function closeActivity() {
      const overlay = document.getElementById('activityOverlay');
      if (!overlay) return;
      overlay.classList.remove('open');
      overlay.classList.add('closing');
      overlay.setAttribute('aria-hidden', 'true');
      document.body.classList.remove('activity-page-open');
      activityOverlayState.isOpen = false;
      activityOverlayState.day = null;
      activityOverlayState.activeExerciseKey = '';
      activityOverlayState.activeExerciseIndex = 0;
      activityOverlayState.exerciseByKey = {};
      window.setTimeout(() => {
        overlay.classList.remove('closing');
      }, ACTIVITY_OVERLAY_TRANSITION_MS);
    }

    function updateProfileStats(bmi, category) {
      const profileBmi = document.getElementById('profileBmiStat');
      const profilePlan = document.getElementById('profilePlanStat');
      const profileMoves = document.getElementById('profileMovesStat');
      const profileTag = document.getElementById('profileCategoryTag');
      const trackedDays = countTrackedActiveDays();
      const completedMoves = currentPlan.reduce((sum, day) => {
        return sum + day.exercises.filter(ex => progressState.completedExercises[workoutExerciseKey(day.title, ex.name)]).length;
      }, 0);
      if (profileBmi) profileBmi.textContent = bmi ? bmi.toFixed(1) : '--';
      if (profilePlan) profilePlan.textContent = trackedDays || 0;
      if (profileMoves) profileMoves.textContent = completedMoves || 0;
      if (profileTag) profileTag.textContent = `@${category.toLowerCase().replace(/\s+/g, '-')}`;
    }
    function renderPlan(planToRender, options = {}) {
      const planList = document.getElementById('planList');
      const planPager = document.getElementById('planPager');
      const planPagerMeta = document.getElementById('planPagerMeta');
      const planPrevBtn = document.getElementById('planPrevBtn');
      const planNextBtn = document.getElementById('planNextBtn');
      const viewNutritionBtn = document.getElementById('viewNutritionBtn');
      planList.innerHTML = '';
      const plan = planToRender || currentPlan || [];
      const weeks = groupPlanByWeek(plan);
      if (!options.keepPage) {
        planViewState.weekPage = 0;
      }
      if (planViewState.weekPage < 0) planViewState.weekPage = 0;
      if (planViewState.weekPage > weeks.length - 1) planViewState.weekPage = Math.max(0, weeks.length - 1);
      if (!plan || plan.length === 0 || weeks.length === 0) {
        if (planPager) planPager.style.display = 'none';
        if (viewNutritionBtn) viewNutritionBtn.style.display = 'none';
        return;
      }
      if (viewNutritionBtn) viewNutritionBtn.style.display = '';
      const weekGroup = weeks[planViewState.weekPage];
      if (planPager) planPager.style.display = '';
      if (planPagerMeta) {
        planPagerMeta.textContent = `${weekGroup.label} â€¢ ${weekGroup.days.length} day${weekGroup.days.length === 1 ? '' : 's'} â€¢ ${planViewState.weekPage + 1}/${weeks.length}`;
      }
      if (planPrevBtn) planPrevBtn.disabled = planViewState.weekPage === 0;
      if (planNextBtn) planNextBtn.disabled = planViewState.weekPage >= weeks.length - 1;

      if (options.animate) {
        planList.classList.remove('plan-slide-in-right', 'plan-slide-in-left');
        void planList.offsetWidth;
        planList.classList.add(planViewState.lastDirection > 0 ? 'plan-slide-in-right' : 'plan-slide-in-left');
        window.setTimeout(() => {
          planList.classList.remove('plan-slide-in-right', 'plan-slide-in-left');
        }, 540);
      }

      weekGroup.days.forEach((day) => {
        const dayCard = document.createElement('div');
        dayCard.classList.add('day-card');
        dayCard.dataset.opening = '0';
        dayCard.setAttribute('role', 'button');
        dayCard.setAttribute('tabindex', '0');
        dayCard.setAttribute('aria-label', `${day.title}. Open workout details`);
        const cardHeader = document.createElement('div');
        cardHeader.classList.add('day-card-header');
        const cardTitleWrap = document.createElement('div');
        const title = document.createElement('p');
        title.classList.add('day-title');
        title.textContent = day.title;
        cardTitleWrap.appendChild(title);
        const focus = document.createElement('p');
        focus.classList.add('day-focus');
        focus.textContent = day.focus;
        cardTitleWrap.appendChild(focus);
        const badge = document.createElement('span');
        badge.classList.add('day-badge');
        const completedDayMoves = day.exercises.filter(ex => progressState.completedExercises[workoutExerciseKey(day.title, ex.name)]).length;
        badge.textContent = `${completedDayMoves}/${day.exercises.length} moves`;
        if (completedDayMoves > 0) badge.classList.add('live');
        if (completedDayMoves === day.exercises.length && day.exercises.length > 0) badge.classList.add('done');
        cardHeader.appendChild(cardTitleWrap);
        cardHeader.appendChild(badge);
        dayCard.appendChild(cardHeader);
        const exerciseList = document.createElement('ul');
        exerciseList.classList.add('exercise-list');
        day.exercises.forEach(ex => {
          const item = document.createElement('li');
          item.classList.add('exercise-item');
          // Create image element for the exercise, if available
      const img = document.createElement('img');
      const imagePath = getExerciseDiagramImage(ex.name);
      if (imagePath) {
        img.src = imagePath;
        img.alt = ex.name;
      } else {
        img.alt = '';
      }
      // Create span for the exercise text
      const textSpan = document.createElement('span');
      textSpan.textContent = `${ex.name} - ${ex.sets} sets - ${ex.reps}`;
      // Append image and text to list item
      item.appendChild(img);
      item.appendChild(textSpan);
          exerciseList.appendChild(item);
        });
        dayCard.appendChild(exerciseList);
        const openFromCard = () => openActivityFromDayCard(dayCard, day);
        let cardTouchStartX = 0;
        let cardTouchStartY = 0;
        dayCard.addEventListener('click', openFromCard);
        dayCard.addEventListener('touchstart', (event) => {
          const touch = event.changedTouches && event.changedTouches[0];
          if (!touch) return;
          cardTouchStartX = touch.clientX;
          cardTouchStartY = touch.clientY;
        }, { passive: true });
        dayCard.addEventListener('touchend', (event) => {
          const touch = event.changedTouches && event.changedTouches[0];
          if (!touch) return;
          const movedX = Math.abs(touch.clientX - cardTouchStartX);
          const movedY = Math.abs(touch.clientY - cardTouchStartY);
          // Ignore scroll gestures; open only for near-stationary taps.
          if (movedX > 10 || movedY > 10) return;
          event.preventDefault();
          openFromCard();
        }, { passive: false });
        dayCard.addEventListener('keydown', (event) => {
          if (event.key === 'Enter' || event.key === ' ') {
            event.preventDefault();
            openFromCard();
          }
        });
        planList.appendChild(dayCard);
      });
      updateActivityTracker();
      updateProfileStats(lastBmi, lastCategory);
    }
    function bmiCategory(bmi) {
      if (bmi < 18.5) return 'Underweight';
      if (bmi < 25) return 'Normal';
      if (bmi < 30) return 'Overweight';
      return 'Obese';
    }
    function restartRevealAnimation(element, delay = 0) {
      if (!element) return;
      element.classList.remove('is-revealed');
      element.classList.remove('reveal-ready');
      // Force a reflow so animation can replay on recalculation.
      void element.offsetWidth;
      element.classList.add('reveal-ready');
      window.setTimeout(() => {
        element.classList.add('is-revealed');
      }, delay);
    }
    function animateBmiDetails(showRisk) {
      const bmiResult = document.getElementById('bmiResult');
      const riskMessage = document.getElementById('riskMessage');
      const planSection = document.getElementById('plan');
      const taglineSection = document.getElementById('tagline');

      restartRevealAnimation(bmiResult, 20);
      if (showRisk && riskMessage) {
        restartRevealAnimation(riskMessage, 110);
      } else if (riskMessage) {
        riskMessage.classList.remove('reveal-ready', 'is-revealed');
      }
      if (planSection) {
        restartRevealAnimation(planSection, 190);
        planSection.classList.remove('plan-revealing');
        void planSection.offsetWidth;
        planSection.classList.add('plan-revealing');
        window.setTimeout(() => planSection.classList.remove('plan-revealing'), 860);
      }
      if (taglineSection) restartRevealAnimation(taglineSection, 290);
    }
    function initializeBmiDefaultState() {
      const pointer = document.getElementById('bmiPointer');
      const bmiResult = document.getElementById('bmiResult');
      const riskMessage = document.getElementById('riskMessage');
      if (pointer && (!pointer.style.left || pointer.style.left === '0%')) {
        pointer.style.left = '40%';
      }
      if (bmiResult && !String(bmiResult.textContent || '').trim()) {
        bmiResult.textContent = 'BMI: -- (Pending)';
      }
      if (riskMessage) {
        riskMessage.style.display = 'none';
        riskMessage.textContent = '';
      }
    }
    function calculateBMI(options = {}) {
      const shouldOpenPlanPage = options.openPlanPage !== false;
      const heightInput = document.getElementById('heightInput');
      const weightInput = document.getElementById('weightInput');
      const ageInput = document.getElementById('ageInput');
      const bodyTypeInput = document.getElementById('bodyTypeInput');
      const genderInput = document.getElementById('genderInput');
      const goalWeeksInput = document.getElementById('goalWeeksInput');
      const fitnessGoalInput = document.getElementById('fitnessGoalInput');
      const activityLevelInput = document.getElementById('activityLevelInput');
      const dietaryPreferenceInput = document.getElementById('dietaryPreferenceInput');
      const allergiesInput = document.getElementById('allergiesInput');
      const experienceInput = document.getElementById('experienceInput');
      const limitationsInput = document.getElementById('limitationsInput');
        const bmiResult = document.getElementById('bmiResult');
        const pointer = document.getElementById('bmiPointer');
        const riskMessage = document.getElementById('riskMessage');
        const heroModeValue = document.getElementById('heroModeValue');
        const height = parseFloat(heightInput.value);
        const weight = parseFloat(weightInput.value);
        const age = clampNumber(ageInput?.value, 10, 90, 28);
        const bodyType = bodyTypeInput?.value || 'mesomorph';
        const gender = String(genderInput?.value || profileState.gender || 'male').toLowerCase() === 'female' ? 'female' : 'male';
        const goalWeeks = clampNumber(goalWeeksInput?.value, 1, 24, 6);
        riskMessage.style.display = 'none';
      riskMessage.textContent = '';
        profileState.gender = gender;
        profileState.fitnessGoal = normalizeGoal(fitnessGoalInput?.value || profileState.fitnessGoal || 'auto');
        profileState.activityLevel = String(activityLevelInput?.value || profileState.activityLevel || 'moderate').toLowerCase();
        profileState.dietaryPreference = String(dietaryPreferenceInput?.value || profileState.dietaryPreference || 'balanced').toLowerCase();
        profileState.allergies = String(allergiesInput?.value || '').trim();
        profileState.experience = String(experienceInput?.value || profileState.experience || 'beginner').toLowerCase();
        profileState.limitations = String(limitationsInput?.value || '').trim();
        saveProfile();
        updateTrackingBodyGraphic();
        updateBodyTypeGuide();
      if (height && weight && height > 0) {
        const meters = height / 100;
        const bmi = weight / (meters * meters);
        const bmiRounded = bmi.toFixed(1);
        const category = bmiCategory(bmi);
        const suggestedGoalWeeks = suggestGoalDurationWeeks(bodyType, age, category, gender);
        if (goalWeeksInput) goalWeeksInput.value = String(suggestedGoalWeeks);
        lastBmi = bmi;
        lastCategory = category;
        bmiResult.textContent = `BMI: ${bmiRounded} (${category})`;
        const adaptiveSettings = deriveAdaptivePlanSettings(category, age, bodyType, suggestedGoalWeeks || goalWeeks, gender);
        currentPlanMeta = adaptiveSettings;
        refreshGoalDurationSuggestion(category);
        if (heroModeValue) {
          const modePrefix = category === 'Obese' ? 'Low impact' : 'Smart';
          heroModeValue.textContent = `${modePrefix}`;
        }
        const min = 15;
        const max = 40;
        const clampedBMI = Math.min(Math.max(bmi, min), max);
        const position = ((clampedBMI - min) / (max - min)) * 100;
        pointer.style.left = `${position}%`;
        // Select plan based on category
        currentPlan = buildAdaptivePlan(category, adaptiveSettings);
        renderPlan(currentPlan);
        updateProfileStats(lastBmi, lastCategory);
        // Show the plan section and tagline
        const planSection = document.getElementById('plan');
        const taglineSection = document.getElementById('tagline');
        if (planSection) planSection.style.display = '';
        if (taglineSection) taglineSection.style.display = '';
        let hasRiskMessage = false;
        if (bmi < 18.5) {
          riskMessage.textContent = 'Underweight increases your risk of nutritional deficiencies, fatigue, and immune issues.';
          riskMessage.style.display = 'block';
          hasRiskMessage = true;
        } else if (bmi >= 25 && bmi < 30) {
          riskMessage.textContent = 'Being overweight can raise your risk of high blood pressure, cholesterol, and heart disease.';
          riskMessage.style.display = 'block';
          hasRiskMessage = true;
        } else if (bmi >= 30) {
          riskMessage.textContent = 'Obesity significantly elevates your risk for diabetes, heart disease, and other chronic conditions.';
          riskMessage.style.display = 'block';
          hasRiskMessage = true;
        }
          if (!options.skipReveal) animateBmiDetails(hasRiskMessage);
          regenerateNutritionPlan();
          if (shouldOpenPlanPage) {
            window.setTimeout(() => {
              showPage('plan');
            }, options.skipReveal ? 40 : 260);
          } else if (!options.skipScroll) {
            window.setTimeout(() => {
              const profileSection = document.getElementById('profile');
              profileSection?.scrollIntoView({ behavior: 'smooth', block: 'start' });
            }, 220);
          }
        } else {
        lastBmi = null;
        lastCategory = 'Smart';
        const fallbackGoalWeeks = suggestGoalDurationWeeks(bodyType, age, 'Smart', gender);
        if (goalWeeksInput) goalWeeksInput.value = String(fallbackGoalWeeks);
        currentPlanMeta = deriveAdaptivePlanSettings('Smart', age, bodyType, fallbackGoalWeeks, gender);
        bmiResult.textContent = 'Please enter valid height and weight.';
        pointer.style.left = '0%';
        if (heroModeValue) heroModeValue.textContent = 'Smart';
          refreshGoalDurationSuggestion('Smart');
          updateProfileStats(lastBmi, lastCategory);
          updateActivityTracker();
          regenerateNutritionPlan();
        }
      }

