    function submenuItemsForButton(button) {
      if (!button) return [];
      if (button.id === 'calculateBtn') return ['Generate plan', 'Adaptive'];
      if (button.id === 'viewNutritionBtn') return ['Open', 'Nutrition'];
      if (button.id === 'regenNutritionBtn') return ['Refresh', 'Meals'];
      if (button.id === 'saveNutritionBtn') return ['Save', 'Plan'];
      if (button.id === 'enableMotionBtn') return ['Motion', 'Hardware'];
      if (button.id === 'planPrevBtn') return ['Previous', 'Week'];
      if (button.id === 'planNextBtn') return ['Next', 'Week'];
      if (button.id === 'coverMenuBtn') return ['Profile', 'Cover'];
      if (button.classList.contains('nav-item')) return ['Switch', button.getAttribute('aria-label') || 'Page'];
      if (button.classList.contains('bodytype-chip')) return ['Body Type', (button.dataset.bodyType || '').replace(/^./, c => c.toUpperCase())];
      const label = (button.getAttribute('aria-label') || button.textContent || '').trim().replace(/\s+/g, ' ');
      if (!label) return [];
      return [label, 'Menu'];
    }

    function showButtonSubmenuFx(button) {
      const fx = document.getElementById('buttonSubmenuFx');
      if (!fx || !button) return;
      const items = submenuItemsForButton(button).filter(Boolean).slice(0, 2);
      if (!items.length) return;
      const rect = button.getBoundingClientRect();
      const menuWidth = Math.max(108, Math.min(window.innerWidth - 20, items.join(' ').length * 8 + 56));
      const left = Math.min(window.innerWidth - menuWidth - 10, Math.max(10, rect.left + rect.width / 2 - menuWidth / 2));
      const top = Math.max(10, rect.top - 44);
      fx.style.left = `${left}px`;
      fx.style.top = `${top}px`;
      fx.innerHTML = `<div class="button-submenu-fx-track">${items.map(item => `<span class="button-submenu-pill">${item}</span>`).join('')}</div>`;
      fx.classList.add('open');
      if (buttonSubmenuFxTimer) window.clearTimeout(buttonSubmenuFxTimer);
      buttonSubmenuFxTimer = window.setTimeout(() => {
        fx.classList.remove('open');
      }, 760);
    }

