    const experienceInputControl = document.getElementById('experienceInput');
    const limitationsInputControl = document.getElementById('limitationsInput');
    [
      fitnessGoalInputControl,
      activityLevelInputControl,
      dietaryPreferenceInputControl,
      allergiesInputControl,
      experienceInputControl,
      limitationsInputControl
    ].forEach(input => {
      if (!input) return;
      input.addEventListener('change', () => {
        if (input === fitnessGoalInputControl) profileState.fitnessGoal = normalizeGoal(input.value);
        if (input === activityLevelInputControl) profileState.activityLevel = String(input.value || 'moderate').toLowerCase();
        if (input === dietaryPreferenceInputControl) profileState.dietaryPreference = String(input.value || 'balanced').toLowerCase();
        if (input === allergiesInputControl) profileState.allergies = String(input.value || '').trim();
        if (input === experienceInputControl) profileState.experience = String(input.value || 'beginner').toLowerCase();
        if (input === limitationsInputControl) profileState.limitations = String(input.value || '').trim();
        saveProfile();
        syncGuidedSetupFlow();
        recalculateDependentPlans();
      });
    });
